var QUESTIONS_THEORY_16 = [
{type:"mcq",diff:"easy",en:{q:"What is the primary concept of Cloud Computing?",opts:["Storing data on local drives","Delivering computing services over the internet","A type of physical server hardware","A new programming language"],ans:1,exp:"Cloud computing is the delivery of computing services over the internet to offer faster innovation and flexible resources. It eliminates the need for maintaining local physical servers. Users pay only for the cloud services they use."},hi:{q:"क्लाउड कंप्यूटिंग की प्राथमिक अवधारणा क्या है?",opts:["स्थानीय ड्राइव पर डेटा स्टोर करना","इंटरनेट पर कंप्यूटिंग सेवाएं प्रदान करना","एक प्रकार का भौतिक सर्वर हार्डवेयर","एक नई प्रोग्रामिंग भाषा"],ans:1,exp:"क्लाउड कंप्यूटिंग इंटरनेट पर कंप्यूटिंग सेवाओं का वितरण है जो लचीले संसाधन प्रदान करता है। यह स्थानीय भौतिक सर्वरों को बनाए रखने की आवश्यकता को समाप्त करता है। उपयोगकर्ता केवल उन क्लाउड सेवाओं के लिए भुगतान करते हैं जिनका वे उपयोग करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is a cloud service model?",opts:["Hardware as a Service (HaaS)","Network as a Service (NaaS)","Software as a Service (SaaS)","Protocol as a Service (PaaS)"],ans:2,exp:"Software as a Service (SaaS) is a popular cloud computing model. It delivers software applications over the internet on a subscription basis. Users can access these applications via a web browser without installing them locally."},hi:{q:"निम्नलिखित में से कौन सा क्लाउड सेवा मॉडल है?",opts:["हार्डवेयर ऐज़ ए सर्विस (HaaS)","नेटवर्क ऐज़ ए सर्विस (NaaS)","सॉफ्टवेयर ऐज़ ए सर्विस (SaaS)","प्रोटोकॉल ऐज़ ए सर्विस (PaaS)"],ans:2,exp:"सॉफ्टवेयर ऐज़ ए सर्विस (SaaS) एक लोकप्रिय क्लाउड कंप्यूटिंग मॉडल है। यह सदस्यता के आधार पर इंटरनेट पर सॉफ्टवेयर एप्लिकेशन प्रदान करता है। उपयोगकर्ता उन्हें स्थानीय रूप से इंस्टॉल किए बिना वेब ब्राउज़र के माध्यम से एक्सेस कर सकते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What does IaaS stand for in cloud computing?",opts:["Internet as a Service","Information as a Service","Infrastructure as a Service","Integration as a Service"],ans:2,exp:"IaaS stands for Infrastructure as a Service, offering essential compute, storage, and networking resources on demand. It provides the highest level of flexibility and management control over IT resources. It is highly scalable and cost-effective."},hi:{q:"क्लाउड कंप्यूटिंग में IaaS का क्या अर्थ है?",opts:["इंटरनेट ऐज़ ए सर्विस","इन्फॉर्मेशन ऐज़ ए सर्विस","इन्फ्रास्ट्रक्चर ऐज़ ए सर्विस","इंटीग्रेशन ऐज़ ए सर्विस"],ans:2,exp:"IaaS का अर्थ इन्फ्रास्ट्रक्चर ऐज़ ए सर्विस है, जो मांग पर आवश्यक कंप्यूट, स्टोरेज और नेटवर्किंग संसाधन प्रदान करता है। यह आईटी संसाधनों पर लचीलेपन और प्रबंधन नियंत्रण का उच्चतम स्तर प्रदान करता है। यह अत्यधिक स्केलेबल है।"}},
{type:"mcq",diff:"easy",en:{q:"Which cloud deployment model is accessible to the general public?",opts:["Private Cloud","Public Cloud","Hybrid Cloud","Community Cloud"],ans:1,exp:"A public cloud is defined as computing services offered by third-party providers over the public Internet. It is available to anyone who wants to use or purchase them. These services may be free or sold on demand."},hi:{q:"कौन सा क्लाउड डिप्लॉयमेंट मॉडल आम जनता के लिए सुलभ है?",opts:["प्राइवेट क्लाउड","पब्लिक क्लाउड","हाइब्रिड क्लाउड","कम्युनिटी क्लाउड"],ans:1,exp:"पब्लिक क्लाउड को सार्वजनिक इंटरनेट पर तीसरे पक्ष के प्रदाताओं द्वारा दी जाने वाली कंप्यूटिंग सेवाओं के रूप में परिभाषित किया गया है। यह उन सभी के लिए उपलब्ध है जो इसका उपयोग करना चाहते हैं। ये सेवाएँ मुफ्त या मांग पर बेची जा सकती हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What does SDLC stand for?",opts:["Software Design Life Cycle","System Development Life Cycle","Software Deployment Local Cloud","System Design Local Code"],ans:1,exp:"SDLC stands for System Development Life Cycle, a process for planning, creating, testing, and deploying an information system. It ensures that high-quality software is produced. It consists of various distinct phases to manage the project."},hi:{q:"SDLC का पूर्ण रूप क्या है?",opts:["सॉफ्टवेयर डिजाइन लाइफ साइकिल","सिस्टम डेवलपमेंट लाइफ साइकिल","सॉफ्टवेयर डिप्लॉयमेंट लोकल क्लाउड","सिस्टम डिजाइन लोकल कोड"],ans:1,exp:"SDLC का अर्थ सिस्टम डेवलपमेंट लाइफ साइकिल है, जो सूचना प्रणाली की योजना बनाने, बनाने, परीक्षण करने और तैनात करने की एक प्रक्रिया है। यह सुनिश्चित करता है कि उच्च गुणवत्ता वाले सॉफ्टवेयर का उत्पादन हो। इसमें विभिन्न चरण शामिल हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which is the first phase of the Application Development Life Cycle?",opts:["Implementation","Testing","Planning and Requirement Analysis","Deployment"],ans:2,exp:"Planning and Requirement Analysis is the fundamental and first stage in the SDLC. It involves gathering requirements from stakeholders and analyzing project feasibility. This phase sets the foundation for the entire software development project."},hi:{q:"एप्लिकेशन डेवलपमेंट लाइफ साइकिल का पहला चरण कौन सा है?",opts:["कार्यान्वयन (Implementation)","परीक्षण (Testing)","योजना और आवश्यकता विश्लेषण","तैनाती (Deployment)"],ans:2,exp:"योजना और आवश्यकता विश्लेषण SDLC में मौलिक और पहला चरण है। इसमें हितधारकों से आवश्यकताएं एकत्र करना और व्यवहार्यता का विश्लेषण करना शामिल है। यह चरण पूरे सॉफ्टवेयर विकास परियोजना की नींव रखता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which cloud model combines both private and public clouds?",opts:["Combined Cloud","Mixed Cloud","Hybrid Cloud","Community Cloud"],ans:2,exp:"A hybrid cloud combines public and private cloud models, allowing data and applications to be shared between them. This gives businesses greater flexibility and more deployment options. It helps optimize existing infrastructure and security."},hi:{q:"कौन सा क्लाउड मॉडल प्राइवेट और पब्लिक क्लाउड दोनों को जोड़ता है?",opts:["कंबाइंड क्लाउड","मिक्स्ड क्लाउड","हाइब्रिड क्लाउड","कम्युनिटी क्लाउड"],ans:2,exp:"हाइब्रिड क्लाउड पब्लिक और प्राइवेट क्लाउड मॉडल को जोड़ता है, जिससे डेटा और एप्लिकेशन साझा किए जा सकते हैं। यह व्यवसायों को अधिक लचीलापन और तैनाती विकल्प देता है। यह मौजूदा बुनियादी ढांचे और सुरक्षा को अनुकूलित करने में मदद करता है।"}},
{type:"mcq",diff:"easy",en:{q:"In which phase of SDLC is the actual code written?",opts:["Design","Testing","Implementation / Coding","Maintenance"],ans:2,exp:"The Implementation or Coding phase is where developers write the actual source code according to the design specifications. This is usually the longest phase of the software development life cycle. The software is built module by module."},hi:{q:"SDLC के किस चरण में वास्तविक कोड लिखा जाता है?",opts:["डिज़ाइन","परीक्षण","कार्यान्वयन / कोडिंग","रखरखाव"],ans:2,exp:"कार्यान्वयन या कोडिंग चरण वह है जहां डेवलपर्स डिजाइन विनिर्देशों के अनुसार वास्तविक स्रोत कोड लिखते हैं। यह आमतौर पर सॉफ्टवेयर विकास जीवन चक्र का सबसे लंबा चरण होता है। सॉफ्टवेयर को मॉड्यूल द्वारा बनाया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of these is an example of a SaaS provider?",opts:["Microsoft Azure Virtual Machines","Amazon EC2","Google Workspace (G-Suite)","Amazon S3"],ans:2,exp:"Google Workspace is an example of SaaS because it provides complete software applications directly over the internet. Users do not need to install or maintain the software on local machines. It is centrally hosted and managed."},hi:{q:"इनमें से कौन सा SaaS प्रदाता का उदाहरण है?",opts:["Microsoft Azure Virtual Machines","Amazon EC2","Google Workspace (G-Suite)","Amazon S3"],ans:2,exp:"Google Workspace SaaS का एक उदाहरण है क्योंकि यह इंटरनेट पर पूर्ण सॉफ्टवेयर एप्लिकेशन प्रदान करता है। उपयोगकर्ताओं को स्थानीय मशीनों पर सॉफ़्टवेयर इंस्टॉल या बनाए रखने की आवश्यकता नहीं है। यह केंद्रीय रूप से होस्ट और प्रबंधित है।"}},
{type:"mcq",diff:"easy",en:{q:"Which phase follows the Coding phase in SDLC?",opts:["Maintenance","Design","Testing","Planning"],ans:2,exp:"The Testing phase immediately follows the Coding phase. Here, the developed software is tested thoroughly to find and fix any bugs or defects. This ensures the product meets the specified requirements and quality standards."},hi:{q:"SDLC में कोडिंग चरण के बाद कौन सा चरण आता है?",opts:["रखरखाव","डिज़ाइन","परीक्षण","प्लानिंग"],ans:2,exp:"परीक्षण चरण तुरंत कोडिंग चरण का अनुसरण करता है। यहां, किसी भी बग या दोष को खोजने और ठीक करने के लिए विकसित सॉफ्टवेयर का पूरी तरह से परीक्षण किया जाता है। यह सुनिश्चित करता है कि उत्पाद निर्दिष्ट आवश्यकताओं को पूरा करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which cloud characteristic allows users to access services without human interaction from the provider?",opts:["Broad network access","On-demand self-service","Resource pooling","Measured service"],ans:1,exp:"On-demand self-service means a consumer can unilaterally provision computing capabilities automatically as needed. There is no need for human interaction with each service provider. Users manage services via a web portal."},hi:{q:"क्लाउड की कौन सी विशेषता उपयोगकर्ताओं को प्रदाता से मानवीय संपर्क के बिना सेवाओं तक पहुंचने की अनुमति देती है?",opts:["व्यापक नेटवर्क पहुंच","ऑन-डिमांड सेल्फ-सर्विस","संसाधन पूलिंग","मापी गई सेवा"],ans:1,exp:"ऑन-डिमांड सेल्फ-सर्विस का मतलब है कि एक उपभोक्ता आवश्यकतानुसार स्वचालित रूप से कंप्यूटिंग क्षमताओं का प्रावधान कर सकता है। प्रदाता के साथ मानवीय बातचीत की कोई आवश्यकता नहीं है। उपयोगकर्ता वेब पोर्टल के माध्यम से सेवाओं का प्रबंधन करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What does PaaS stand for?",opts:["Platform as a Service","Programming as a Service","Process as a Service","Public as a Service"],ans:0,exp:"PaaS stands for Platform as a Service, which provides a framework for developers to build, test, and deploy applications. It abstracts the underlying infrastructure management. Developers focus entirely on application logic."},hi:{q:"PaaS का पूर्ण रूप क्या है?",opts:["प्लेटफ़ॉर्म ऐज़ ए सर्विस","प्रोग्रामिंग ऐज़ ए सर्विस","प्रोसेस ऐज़ ए सर्विस","पब्लिक ऐज़ ए सर्विस"],ans:0,exp:"PaaS का अर्थ प्लेटफ़ॉर्म ऐज़ ए सर्विस है, जो डेवलपर्स को एप्लिकेशन बनाने, परीक्षण करने और तैनात करने के लिए एक ढांचा प्रदान करता है। यह अंतर्निहित बुनियादी ढांचे के प्रबंधन को छुपाता है। डेवलपर्स केवल एप्लिकेशन लॉजिक पर ध्यान केंद्रित करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which role is responsible for testing the application in SDLC?",opts:["Developer","Business Analyst","Quality Assurance (QA) Tester","Project Manager"],ans:2,exp:"The Quality Assurance (QA) Tester is responsible for testing the software to identify defects and ensure it works as intended. They create test cases based on the requirements. They work closely with developers to resolve issues."},hi:{q:"SDLC में एप्लिकेशन का परीक्षण करने के लिए कौन सी भूमिका जिम्मेदार है?",opts:["डेवलपर","व्यापार विश्लेषक","क्वालिटी एश्योरेंस (QA) टेस्टर","प्रोजेक्ट मैनेजर"],ans:2,exp:"क्वालिटी एश्योरेंस (QA) टेस्टर सॉफ़्टवेयर का परीक्षण करने और यह सुनिश्चित करने के लिए ज़िम्मेदार है कि यह ठीक से काम करता है। वे आवश्यकताओं के आधार पर परीक्षण केस बनाते हैं। वे समस्याओं को हल करने के लिए डेवलपर्स के साथ मिलकर काम करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which of these is a major benefit of cloud computing?",opts:["Higher upfront hardware cost","Limited scalability","Pay-as-you-go pricing model","Need for large local physical space"],ans:2,exp:"The pay-as-you-go pricing model is a significant benefit of cloud computing. It converts capital expenditure into operational expenditure. Organizations only pay for the exact resources they consume."},hi:{q:"इनमें से कौन सा क्लाउड कंप्यूटिंग का एक प्रमुख लाभ है?",opts:["उच्च अग्रिम हार्डवेयर लागत","सीमित स्केलेबिलिटी","पे-एज़-यू-गो प्राइसिंग मॉडल","बड़े स्थानीय भौतिक स्थान की आवश्यकता"],ans:2,exp:"पे-एज़-यू-गो प्राइसिंग मॉडल क्लाउड कंप्यूटिंग का एक महत्वपूर्ण लाभ है। यह पूंजीगत व्यय को परिचालन व्यय में परिवर्तित करता है। संगठन केवल उन्हीं संसाधनों के लिए भुगतान करते हैं जिनका वे उपभोग करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"In SDLC, what is done during the Maintenance phase?",opts:["Writing the initial code","Gathering project requirements","Fixing issues and updating the software post-release","Creating wireframes"],ans:2,exp:"The Maintenance phase occurs after the software is deployed to the production environment. It involves fixing newly discovered bugs, updating the software, and adding new features. This ensures the software remains functional and relevant."},hi:{q:"SDLC में, रखरखाव चरण के दौरान क्या किया जाता है?",opts:["प्रारंभिक कोड लिखना","परियोजना आवश्यकताओं को इकट्ठा करना","रिलीज के बाद समस्याओं को ठीक करना और सॉफ्टवेयर को अपडेट करना","वायरफ्रेम बनाना"],ans:2,exp:"सॉफ़्टवेयर को उत्पादन वातावरण में तैनात किए जाने के बाद रखरखाव चरण होता है। इसमें नए खोजे गए बग को ठीक करना और नए फीचर जोड़ना शामिल है। यह सुनिश्चित करता है कि सॉफ्टवेयर कार्यात्मक और प्रासंगिक बना रहे।"}},
{type:"mcq",diff:"easy",en:{q:"Which type of cloud is exclusively used by a single organization?",opts:["Public Cloud","Private Cloud","Hybrid Cloud","Community Cloud"],ans:1,exp:"A private cloud consists of computing resources used exclusively by one business or organization. It can be physically located on the company's on-site datacenter or hosted by a third-party. It provides enhanced security and privacy."},hi:{q:"किस प्रकार के क्लाउड का उपयोग विशेष रूप से एकल संगठन द्वारा किया जाता है?",opts:["पब्लिक क्लाउड","प्राइवेट क्लाउड","हाइब्रिड क्लाउड","कम्युनिटी क्लाउड"],ans:1,exp:"एक प्राइवेट क्लाउड में विशेष रूप से एक व्यवसाय या संगठन द्वारा उपयोग किए जाने वाले कंप्यूटिंग संसाधन होते हैं। यह भौतिक रूप से कंपनी के डेटासेंटर पर स्थित हो सकता है। यह उन्नत सुरक्षा और गोपनीयता प्रदान करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does the term 'Deployment' mean in SDLC?",opts:["Designing the database","Releasing the software to end users","Testing the system","Collecting user feedback"],ans:1,exp:"Deployment is the phase where the finalized software is released to the production environment for end users to access. It might be released in stages or all at once. Proper deployment ensures the system goes live smoothly."},hi:{q:"SDLC में 'डिप्लॉयमेंट' (Deployment) शब्द का क्या अर्थ है?",opts:["डेटाबेस डिजाइन करना","अंतिम उपयोगकर्ताओं के लिए सॉफ्टवेयर जारी करना","सिस्टम का परीक्षण करना","उपयोगकर्ता प्रतिक्रिया एकत्र करना"],ans:1,exp:"डिप्लॉयमेंट वह चरण है जहां अंतिम सॉफ़्टवेयर को अंतिम उपयोगकर्ताओं के उपयोग के लिए उत्पादन वातावरण में जारी किया जाता है। इसे चरणों में या एक साथ जारी किया जा सकता है। उचित डिप्लॉयमेंट सुचारू लाइव सुनिश्चित करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following describes 'Scalability' in cloud computing?",opts:["Inability to handle more users","The ability to quickly increase or decrease resources","Restricting access to resources","Encrypting all data"],ans:1,exp:"Scalability is the ability of cloud services to dynamically allocate more or fewer resources based on demand. This ensures optimal performance during traffic spikes. It prevents over-provisioning and saves costs."},hi:{q:"निम्नलिखित में से कौन क्लाउड कंप्यूटिंग में 'स्केलेबिलिटी' का वर्णन करता है?",opts:["अधिक उपयोगकर्ताओं को संभालने में असमर्थता","संसाधनों को जल्दी से बढ़ाने या घटाने की क्षमता","संसाधनों तक पहुंच को प्रतिबंधित करना","सभी डेटा को एन्क्रिप्ट करना"],ans:1,exp:"स्केलेबिलिटी क्लाउड सेवाओं की मांग के आधार पर गतिशील रूप से अधिक या कम संसाधनों को आवंटित करने की क्षमता है। यह ट्रैफिक स्पाइक्स के दौरान इष्टतम प्रदर्शन सुनिश्चित करता है। यह ओवर-प्रोविजनिंग को रोकता है और लागत बचाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Who translates business requirements into technical specifications in SDLC?",opts:["Database Administrator","System Analyst / Architect","Quality Tester","End User"],ans:1,exp:"The System Analyst or Architect is responsible for translating user and business requirements into technical design specifications. They bridge the gap between business stakeholders and the development team. They create the system architecture."},hi:{q:"SDLC में व्यावसायिक आवश्यकताओं को तकनीकी विशिष्टताओं में कौन अनुवाद करता है?",opts:["डेटाबेस एडमिनिस्ट्रेटर","सिस्टम एनालिस्ट / आर्किटेक्ट","क्वालिटी टेस्टर","अंतिम उपयोगकर्ता"],ans:1,exp:"सिस्टम एनालिस्ट उपयोगकर्ता और व्यावसायिक आवश्यकताओं को तकनीकी डिजाइन विनिर्देशों में अनुवाद करने के लिए जिम्मेदार है। वे व्यावसायिक हितधारकों और विकास दल के बीच की खाई को पाटते हैं। वे सिस्टम आर्किटेक्चर बनाते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Google Drive and Dropbox are examples of which cloud service?",opts:["Cloud Storage","Cloud Computing Hardware","Local Backup","PaaS Database"],ans:0,exp:"Google Drive and Dropbox are classic examples of cloud storage services. They allow users to store files online and sync them across multiple devices. Users can access their data from anywhere with an internet connection."},hi:{q:"Google Drive और Dropbox किस क्लाउड सेवा के उदाहरण हैं?",opts:["क्लाउड स्टोरेज","क्लाउड कंप्यूटिंग हार्डवेयर","लोकल बैकअप","PaaS डेटाबेस"],ans:0,exp:"Google Drive और Dropbox क्लाउड स्टोरेज सेवाओं के क्लासिक उदाहरण हैं। वे उपयोगकर्ताओं को ऑनलाइन फ़ाइलें संग्रहीत करने और उन्हें कई उपकरणों में सिंक करने की अनुमति देते हैं। उपयोगकर्ता कहीं से भी अपने डेटा तक पहुंच सकते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which phase of SDLC involves creating diagrams and screen layouts?",opts:["Design","Maintenance","Testing","Deployment"],ans:0,exp:"The Design phase involves creating the system's architecture, user interface layouts, database models, and flow diagrams. It provides a blueprint for the developers to follow during coding. It translates requirements into visual formats."},hi:{q:"SDLC के किस चरण में आरेख (diagrams) और स्क्रीन लेआउट बनाना शामिल है?",opts:["डिज़ाइन","रखरखाव","परीक्षण","डिप्लॉयमेंट"],ans:0,exp:"डिज़ाइन चरण में सिस्टम की वास्तुकला, उपयोगकर्ता इंटरफ़ेस लेआउट, डेटाबेस मॉडल और फ्लो आरेख बनाना शामिल है। यह डेवलपर्स को कोडिंग के दौरान पालन करने के लिए एक खाका प्रदान करता है। यह आवश्यकताओं को दृश्य प्रारूपों में अनुवाद करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is 'Web Hosting in Cloud'?",opts:["Hosting a website on a single local physical server","Hosting a website on virtual servers pulling computing resources from extensive underlying networks","Storing website files on a USB drive","Running a website without internet"],ans:1,exp:"Cloud web hosting uses the resources of several clustered servers to host websites, rather than relying on a single traditional server. It ensures high availability and load balancing. It is highly scalable compared to traditional hosting."},hi:{q:"'क्लाउड में वेब होस्टिंग' क्या है?",opts:["एकल स्थानीय भौतिक सर्वर पर वेबसाइट होस्ट करना","व्यापक अंतर्निहित नेटवर्क से संसाधन खींचकर वर्चुअल सर्वर पर वेबसाइट होस्ट करना","USB ड्राइव पर वेबसाइट फ़ाइलें संग्रहीत करना","बिना इंटरनेट के वेबसाइट चलाना"],ans:1,exp:"क्लाउड वेब होस्टिंग एकल पारंपरिक सर्वर पर निर्भर रहने के बजाय वेबसाइटों को होस्ट करने के लिए कई क्लस्टर सर्वरों के संसाधनों का उपयोग करती है। यह उच्च उपलब्धता और लोड संतुलन सुनिश्चित करता है। यह पारंपरिक होस्टिंग की तुलना में अत्यधिक स्केलेबल है।"}},
{type:"mcq",diff:"easy",en:{q:"Which document is generally produced at the end of the Requirement Analysis phase?",opts:["User Manual","Source Code File","Software Requirement Specification (SRS)","Test Case Document"],ans:2,exp:"The Software Requirement Specification (SRS) document is created after requirement gathering. It comprehensively details what the software system will do and how it will be expected to perform. It acts as an agreement between clients and developers."},hi:{q:"आवश्यकता विश्लेषण चरण के अंत में आमतौर पर कौन सा दस्तावेज़ तैयार किया जाता है?",opts:["यूजर मैन्युअल","सोर्स कोड फाइल","सॉफ्टवेयर आवश्यकता विशिष्टता (SRS)","टेस्ट केस दस्तावेज़"],ans:2,exp:"आवश्यकता एकत्र करने के बाद सॉफ्टवेयर आवश्यकता विशिष्टता (SRS) दस्तावेज़ बनाया जाता है। यह विस्तार से बताता है कि सिस्टम क्या करेगा और कैसे काम करेगा। यह ग्राहकों और डेवलपर्स के बीच एक समझौते के रूप में कार्य करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which is NOT a primary cloud computing service model?",opts:["IaaS","SaaS","PaaS","ISP"],ans:3,exp:"ISP (Internet Service Provider) is a company that provides internet access, not a cloud service model. The primary cloud service models are IaaS, PaaS, and SaaS. They represent different layers of cloud resources."},hi:{q:"इनमें से कौन सा प्राथमिक क्लाउड कंप्यूटिंग सेवा मॉडल नहीं है?",opts:["IaaS","SaaS","PaaS","ISP"],ans:3,exp:"ISP (इंटरनेट सर्विस प्रोवाइडर) एक कंपनी है जो इंटरनेट एक्सेस प्रदान करती है, क्लाउड सेवा मॉडल नहीं। प्राथमिक क्लाउड सेवा मॉडल IaaS, PaaS और SaaS हैं। वे क्लाउड संसाधनों की विभिन्न परतों का प्रतिनिधित्व करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What does 'Resource Pooling' mean in Cloud Computing?",opts:["Assigning one server per user permanently","Sharing physical resources among multiple consumers dynamically","Swimming pools in IT companies","Keeping all resources turned off"],ans:1,exp:"Resource pooling means the provider's computing resources are pooled to serve multiple consumers using a multi-tenant model. Physical and virtual resources are dynamically assigned and reassigned according to demand. The user generally has no control over the exact location of the resources."},hi:{q:"क्लाउड कंप्यूटिंग में 'रिसोर्स पूलिंग' का क्या अर्थ है?",opts:["प्रति उपयोगकर्ता स्थायी रूप से एक सर्वर असाइन करना","कई उपभोक्ताओं के बीच भौतिक संसाधनों को गतिशील रूप से साझा करना","आईटी कंपनियों में स्विमिंग पूल","सभी संसाधनों को बंद रखना"],ans:1,exp:"रिसोर्स पूलिंग का मतलब है कि मल्टी-टेनेंट मॉडल का उपयोग करके कई उपभोक्ताओं की सेवा के लिए प्रदाता के संसाधनों को एक साथ रखा जाता है। मांग के अनुसार भौतिक और आभासी संसाधनों को गतिशील रूप से सौंपा जाता है। उपयोगकर्ता का आमतौर पर संसाधनों के सटीक स्थान पर कोई नियंत्रण नहीं होता है।"}},
{type:"mcq",diff:"easy",en:{q:"Who defines the business goals and funding for an application project?",opts:["Project Sponsor / Stakeholder","Database Administrator","UI/UX Designer","Tester"],ans:0,exp:"The Project Sponsor or Stakeholder is the individual or group who provides the financial resources and defines the high-level business goals for the project. They have the ultimate authority over project approval. They ensure the project aligns with business objectives."},hi:{q:"एप्लिकेशन प्रोजेक्ट के लिए व्यावसायिक लक्ष्यों और धन को कौन परिभाषित करता है?",opts:["प्रोजेक्ट स्पॉन्सर / स्टेकहोल्डर","डेटाबेस एडमिनिस्ट्रेटर","UI/UX डिज़ाइनर","टेस्टर"],ans:0,exp:"प्रोजेक्ट स्पॉन्सर या स्टेकहोल्डर वह व्यक्ति या समूह है जो वित्तीय संसाधन प्रदान करता है और व्यावसायिक लक्ष्यों को परिभाषित करता है। परियोजना अनुमोदन पर उनका अंतिम अधिकार है। वे सुनिश्चित करते हैं कि परियोजना व्यावसायिक उद्देश्यों के साथ संरेखित हो।"}},
{type:"mcq",diff:"easy",en:{q:"What is a major disadvantage of Cloud Computing?",opts:["Low initial cost","Requirement of a constant Internet connection","High scalability","Automatic software updates"],ans:1,exp:"A constant and reliable internet connection is mandatory to access cloud services. If the internet goes down, users cannot access their data or applications. This dependence is a primary disadvantage of cloud computing."},hi:{q:"क्लाउड कंप्यूटिंग का एक बड़ा नुकसान क्या है?",opts:["कम प्रारंभिक लागत","निरंतर इंटरनेट कनेक्शन की आवश्यकता","उच्च स्केलेबिलिटी","स्वचालित सॉफ्टवेयर अपडेट"],ans:1,exp:"क्लाउड सेवाओं तक पहुंचने के लिए एक निरंतर और विश्वसनीय इंटरनेट कनेक्शन अनिवार्य है। यदि इंटरनेट बंद हो जाता है, तो उपयोगकर्ता अपने डेटा तक नहीं पहुंच सकते हैं। यह निर्भरता क्लाउड कंप्यूटिंग का एक प्राथमिक नुकसान है।"}},
{type:"mcq",diff:"easy",en:{q:"Which SDLC phase focuses on user training and system handover?",opts:["Deployment / Implementation","Analysis","Coding","Testing"],ans:0,exp:"During the Deployment phase, the system is handed over to the client or users. This phase often includes training the end-users and providing manuals. It ensures users know how to operate the new software effectively."},hi:{q:"कौन सा SDLC चरण उपयोगकर्ता प्रशिक्षण और सिस्टम हैंडओवर पर केंद्रित है?",opts:["डिप्लॉयमेंट / कार्यान्वयन","विश्लेषण","कोडिंग","परीक्षण"],ans:0,exp:"डिप्लॉयमेंट चरण के दौरान, सिस्टम क्लाइंट या उपयोगकर्ताओं को सौंप दिया जाता है। इस चरण में अक्सर अंतिम उपयोगकर्ताओं को प्रशिक्षित करना और मैनुअल प्रदान करना शामिल होता है। यह सुनिश्चित करता है कि उपयोगकर्ता जानते हैं कि सॉफ्टवेयर को प्रभावी ढंग से कैसे संचालित किया जाए।"}},
{type:"tf",diff:"easy",en:{q:"SaaS applications require users to manually install updates on their local computers.",opts:["True","False"],ans:1,exp:"False. In the SaaS model, the cloud provider manages the software, including all updates and patches. Users automatically access the most up-to-date version via their web browsers without any manual installation."},hi:{q:"SaaS अनुप्रयोगों के लिए उपयोगकर्ताओं को अपने स्थानीय कंप्यूटरों पर मैन्युअल रूप से अपडेट स्थापित करने की आवश्यकता होती है।",opts:["सही","गलत"],ans:1,exp:"गलत। SaaS मॉडल में, क्लाउड प्रदाता सभी अपडेट और पैच सहित सॉफ़्टवेयर का प्रबंधन करता है। उपयोगकर्ता बिना किसी मैन्युअल इंस्टॉलेशन के अपने वेब ब्राउज़र के माध्यम से सबसे अद्यतित संस्करण तक पहुंचते हैं।"}},
{type:"tf",diff:"easy",en:{q:"The SDLC is a continuous process that doesn't necessarily end after deployment.",opts:["True","False"],ans:0,exp:"True. The SDLC includes a maintenance phase that continues as long as the software is in use. Software requires ongoing updates, bug fixes, and enhancements over its lifetime. The cycle often restarts for major updates."},hi:{q:"SDLC एक सतत प्रक्रिया है जो डिप्लॉयमेंट के बाद आवश्यक रूप से समाप्त नहीं होती है।",opts:["सही","गलत"],ans:0,exp:"सही। SDLC में एक रखरखाव चरण शामिल है जो तब तक जारी रहता है जब तक कि सॉफ़्टवेयर उपयोग में हो। सॉफ़्टवेयर को अपने जीवनकाल में निरंतर अपडेट और संवर्द्धन की आवश्यकता होती है। प्रमुख अपडेट के लिए चक्र अक्सर फिर से शुरू होता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following best describes Platform as a Service (PaaS)?",opts:["It provides virtual machines and raw storage","It provides an environment for developers to build and deploy apps","It delivers fully functional software to end-users","It offers local desktop virtualization"],ans:1,exp:"Platform as a Service (PaaS) provides a cloud-based environment with everything required to support the complete lifecycle of building and delivering web applications. It includes development tools, databases, and middleware. Developers do not manage the underlying servers."},hi:{q:"निम्नलिखित में से कौन सा प्लेटफॉर्म ऐज़ ए सर्विस (PaaS) का सबसे अच्छा वर्णन करता है?",opts:["यह वर्चुअल मशीन और रॉ स्टोरेज प्रदान करता है","यह डेवलपर्स को ऐप बनाने और तैनात करने के लिए एक वातावरण प्रदान करता है","यह अंतिम उपयोगकर्ताओं को पूरी तरह से कार्यात्मक सॉफ्टवेयर प्रदान करता है","यह स्थानीय डेस्कटॉप वर्चुअलाइजेशन प्रदान करता है"],ans:1,exp:"प्लेटफ़ॉर्म ऐज़ ए सर्विस (PaaS) वेब एप्लिकेशन बनाने और वितरित करने के पूरे जीवनचक्र का समर्थन करने के लिए एक क्लाउड-आधारित वातावरण प्रदान करता है। इसमें विकास उपकरण, डेटाबेस और मिडलवेयर शामिल हैं। डेवलपर्स अंतर्निहित सर्वर का प्रबंधन नहीं करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"In a hybrid cloud environment, what is 'Cloud Bursting'?",opts:["When a server crashes due to overload","Using public cloud resources when private cloud capacity is reached","Hacking into a cloud server","Deleting cloud data permanently"],ans:1,exp:"Cloud bursting is an application deployment model in a hybrid cloud where an application runs in a private cloud and bursts into a public cloud when the demand for computing capacity spikes. This ensures uninterrupted service. It avoids the need to over-provision private infrastructure."},hi:{q:"हाइब्रिड क्लाउड वातावरण में, 'क्लाउड बर्स्टिंग' क्या है?",opts:["जब ओवरलोड के कारण सर्वर क्रैश हो जाता है","निजी क्लाउड क्षमता तक पहुंचने पर सार्वजनिक क्लाउड संसाधनों का उपयोग करना","क्लाउड सर्वर को हैक करना","क्लाउड डेटा को स्थायी रूप से हटाना"],ans:1,exp:"क्लाउड बर्स्टिंग एक हाइब्रिड क्लाउड में एक एप्लिकेशन डिप्लॉयमेंट मॉडल है जहां एक एप्लिकेशन निजी क्लाउड में चलता है और क्षमता की मांग बढ़ने पर सार्वजनिक क्लाउड में फट जाता है। यह निर्बाध सेवा सुनिश्चित करता है। यह निजी बुनियादी ढांचे के अति-प्रावधान से बचाता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following is a key advantage of Cloud Web Hosting over Shared Web Hosting?",opts:["It shares a single physical server's resources","It uses multiple clustered servers to balance the load","It has zero cost","It does not require the internet"],ans:1,exp:"Unlike shared hosting which relies on a single server, cloud hosting spreads the load across multiple clustered servers. If one server goes down, another takes its place, maximizing uptime. This architecture provides excellent reliability and scalability."},hi:{q:"शेयर्ड वेब होस्टिंग की तुलना में क्लाउड वेब होस्टिंग का मुख्य लाभ निम्नलिखित में से कौन सा है?",opts:["यह एकल भौतिक सर्वर के संसाधनों को साझा करता है","यह लोड को संतुलित करने के लिए कई क्लस्टर सर्वर का उपयोग करता है","इसकी कीमत शून्य है","इसे इंटरनेट की आवश्यकता नहीं है"],ans:1,exp:"शेयर्ड होस्टिंग के विपरीत जो एकल सर्वर पर निर्भर करता है, क्लाउड होस्टिंग कई क्लस्टर सर्वरों में लोड फैलाता है। यदि एक सर्वर बंद हो जाता है, तो दूसरा उसका स्थान ले लेता है, जिससे अपटाइम अधिकतम हो जाता है। यह उत्कृष्ट विश्वसनीयता प्रदान करता है।"}},
{type:"mcq",diff:"medium",en:{q:"During which SDLC phase are Use Case diagrams and Data Flow Diagrams (DFDs) heavily utilized?",opts:["Testing","Design","Deployment","Maintenance"],ans:1,exp:"Use Case diagrams and Data Flow Diagrams are essential tools in the Design and Analysis phases. They help visualize how data flows through the system and how users interact with it. These diagrams guide developers in structuring the system correctly."},hi:{q:"किस SDLC चरण के दौरान यूज़ केस डायग्राम और डेटा फ्लो डायग्राम (DFD) का भारी उपयोग किया जाता है?",opts:["परीक्षण","डिज़ाइन","डिप्लॉयमेंट","रखरखाव"],ans:1,exp:"यूज़ केस डायग्राम और डेटा फ्लो डायग्राम डिज़ाइन और विश्लेषण चरणों में आवश्यक उपकरण हैं। वे यह कल्पना करने में मदद करते हैं कि सिस्टम के माध्यम से डेटा कैसे प्रवाहित होता है और उपयोगकर्ता इसके साथ कैसे बातचीत करते हैं। ये डेवलपर्स का मार्गदर्शन करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"What is 'Vendor Lock-in' in cloud computing?",opts:["Securing the cloud server with a physical lock","The difficulty of moving from one cloud provider to another","Locking user accounts after failed login attempts","A feature that prevents unauthorized access"],ans:1,exp:"Vendor lock-in refers to a situation where a customer becomes dependent on a specific cloud provider's technologies or services and cannot easily transition to another provider without substantial costs or legal constraints. It is a major risk when adopting proprietary cloud technologies. Organizations mitigate this by using standardized APIs."},hi:{q:"क्लाउड कंप्यूटिंग में 'वेंडर लॉक-इन' क्या है?",opts:["भौतिक लॉक के साथ क्लाउड सर्वर को सुरक्षित करना","एक क्लाउड प्रदाता से दूसरे में जाने की कठिनाई","विफल लॉगिन के बाद उपयोगकर्ता खातों को लॉक करना","एक विशेषता जो अनधिकृत पहुंच को रोकती है"],ans:1,exp:"वेंडर लॉक-इन एक ऐसी स्थिति है जहां एक ग्राहक एक विशिष्ट क्लाउड प्रदाता पर निर्भर हो जाता है और पर्याप्त लागत के बिना आसानी से दूसरे प्रदाता में संक्रमण नहीं कर सकता है। मालिकाना क्लाउड तकनीकों को अपनाते समय यह एक बड़ा जोखिम है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the role of a Database Administrator (DBA) in application development?",opts:["Designing the user interface","Managing and securing the application's data repositories","Writing the core business logic code","Testing the application for bugs"],ans:1,exp:"The Database Administrator is responsible for designing, implementing, and maintaining the database system. They ensure data integrity, security, and optimal performance of database queries. They work closely with developers to structure the backend data effectively."},hi:{q:"एप्लिकेशन विकास में डेटाबेस एडमिनिस्ट्रेटर (DBA) की क्या भूमिका है?",opts:["यूजर इंटरफेस डिजाइन करना","एप्लिकेशन के डेटा रिपॉजिटरी का प्रबंधन और सुरक्षा करना","कोर बिजनेस लॉजिक कोड लिखना","बग के लिए एप्लिकेशन का परीक्षण करना"],ans:1,exp:"डेटाबेस एडमिनिस्ट्रेटर डेटाबेस सिस्टम को डिजाइन, कार्यान्वित और बनाए रखने के लिए जिम्मेदार है। वे डेटाबेस प्रश्नों की डेटा अखंडता, सुरक्षा और इष्टतम प्रदर्शन सुनिश्चित करते हैं। वे बैकएंड डेटा को प्रभावी ढंग से तैयार करने के लिए डेवलपर्स के साथ काम करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which AWS service is an example of Infrastructure as a Service (IaaS)?",opts:["Amazon EC2 (Elastic Compute Cloud)","AWS Elastic Beanstalk","Amazon WorkMail","Amazon RDS"],ans:0,exp:"Amazon EC2 provides resizable compute capacity in the cloud, acting as raw virtual servers. Users have full control over the operating system and installed software. It is a fundamental example of the IaaS model."},hi:{q:"कौन सी AWS सेवा इन्फ्रास्ट्रक्चर ऐज़ ए सर्विस (IaaS) का एक उदाहरण है?",opts:["Amazon EC2 (इलास्टिक कंप्यूट क्लाउड)","AWS इलास्टिक बीनस्टॉक","Amazon WorkMail","Amazon RDS"],ans:0,exp:"Amazon EC2 क्लाउड में आकार बदलने योग्य कंप्यूट क्षमता प्रदान करता है, जो रॉ वर्चुअल सर्वर के रूप में कार्य करता है। उपयोगकर्ताओं का ऑपरेटिंग सिस्टम और स्थापित सॉफ़्टवेयर पर पूर्ण नियंत्रण होता है। यह IaaS मॉडल का एक मूलभूत उदाहरण है।"}},
{type:"mcq",diff:"medium",en:{q:"In SDLC, what is User Acceptance Testing (UAT)?",opts:["Testing done by developers to check unit code","Testing done by the actual end-users to validate the system against their requirements","Testing the server hardware","Testing the network security"],ans:1,exp:"User Acceptance Testing (UAT) is the final phase of software testing. It is performed by the intended audience or business representatives to verify that the system is ready for real-world use. Passing UAT is typically required before final deployment."},hi:{q:"SDLC में, यूजर एक्सेप्टेंस टेस्टिंग (UAT) क्या है?",opts:["यूनिट कोड की जांच करने के लिए डेवलपर्स द्वारा किया गया परीक्षण","सिस्टम को उनकी आवश्यकताओं के विरुद्ध मान्य करने के लिए वास्तविक अंतिम उपयोगकर्ताओं द्वारा किया गया परीक्षण","सर्वर हार्डवेयर का परीक्षण","नेटवर्क सुरक्षा का परीक्षण"],ans:1,exp:"यूजर एक्सेप्टेंस टेस्टिंग (UAT) सॉफ्टवेयर परीक्षण का अंतिम चरण है। यह लक्षित दर्शकों या व्यावसायिक प्रतिनिधियों द्वारा यह सत्यापित करने के लिए किया जाता है कि सिस्टम उपयोग के लिए तैयार है। अंतिम तैनाती से पहले UAT पास करना आवश्यक है।"}},
{type:"mcq",diff:"medium",en:{q:"What does the term 'Elasticity' refer to in Cloud Computing?",opts:["The physical flexibility of server cables","The ability of a cloud environment to automatically provision and de-provision resources based on workload","Encrypting data in transit","Compressing files for storage"],ans:1,exp:"Elasticity is the degree to which a system is able to adapt to workload changes by provisioning and de-provisioning resources automatically. It allows systems to handle sudden spikes in traffic gracefully. It ensures optimal resource utilization."},hi:{q:"क्लाउड कंप्यूटिंग में 'इलास्टिसिटी' (Elasticity) शब्द का क्या अर्थ है?",opts:["सर्वर केबल का भौतिक लचीलापन","कार्यभार के आधार पर संसाधनों को स्वचालित रूप से प्रावधान और डी-प्रावधान करने के लिए क्लाउड वातावरण की क्षमता","डेटा को एन्क्रिप्ट करना","भंडारण के लिए फ़ाइलों को संपीड़ित करना"],ans:1,exp:"इलास्टिसिटी वह डिग्री है जिस तक कोई सिस्टम संसाधनों को स्वचालित रूप से आवंटित करके कार्यभार परिवर्तनों के अनुकूल होने में सक्षम है। यह सिस्टम को ट्रैफ़िक में अचानक स्पाइक्स को संभालने की अनुमति देता है। यह इष्टतम संसाधन उपयोग सुनिश्चित करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which SDLC model strictly requires one phase to be completed before the next phase begins?",opts:["Agile Model","Waterfall Model","Spiral Model","Iterative Model"],ans:1,exp:"The Waterfall Model is a linear sequential design approach. Progression flows largely in one direction downwards (like a waterfall) through the phases of conception, initiation, analysis, design, construction, testing, and deployment. You cannot overlap phases."},hi:{q:"किस SDLC मॉडल में अगले चरण के शुरू होने से पहले एक चरण को पूरा करना कड़ाई से आवश्यक है?",opts:["एजाइल मॉडल","वाटरफॉल मॉडल","स्पाइरल मॉडल","पुनरावृत्त (Iterative) मॉडल"],ans:1,exp:"वाटरफॉल मॉडल एक रैखिक अनुक्रमिक डिजाइन दृष्टिकोण है। प्रगति मुख्य रूप से चरणों के माध्यम से एक दिशा में नीचे की ओर (एक झरने की तरह) बहती है। आप चरणों को ओवरलैप नहीं कर सकते।"}},
{type:"mcq",diff:"medium",en:{q:"What is 'Multi-tenancy' in cloud computing?",opts:["A single tenant using multiple clouds","A software architecture where a single instance of software serves multiple customers","Tenants renting physical office space","Using multiple operating systems on one PC"],ans:1,exp:"Multi-tenancy refers to a software architecture in which a single instance of software runs on a server and serves multiple tenants (customers). Each tenant's data is isolated and remains invisible to other tenants. It is highly cost-efficient and standard in SaaS."},hi:{q:"क्लाउड कंप्यूटिंग में 'मल्टी-टेनेंसी' क्या है?",opts:["कई क्लाउड का उपयोग करने वाला एक किरायेदार","एक सॉफ्टवेयर आर्किटेक्चर जहां सॉफ्टवेयर का एक उदाहरण कई ग्राहकों की सेवा करता है","भौतिक कार्यालय स्थान किराए पर लेने वाले किरायेदार","एक पीसी पर कई ओएस का उपयोग करना"],ans:1,exp:"मल्टी-टेनेंसी एक सॉफ्टवेयर आर्किटेक्चर है जिसमें सॉफ्टवेयर का एक उदाहरण सर्वर पर चलता है और कई ग्राहकों की सेवा करता है। प्रत्येक किरायेदार का डेटा अलग होता है और अन्य किरायेदारों के लिए अदृश्य रहता है। यह अत्यधिक लागत-कुशल और SaaS में मानक है।"}},
{type:"mcq",diff:"medium",en:{q:"Who writes the unit tests in the Application Development Life Cycle?",opts:["System Administrator","Project Sponsor","Software Developer","Technical Writer"],ans:2,exp:"Software Developers are generally responsible for writing and executing unit tests. Unit tests verify the functionality of a specific section of code, usually at the function or method level. This catches bugs early in the development cycle."},hi:{q:"एप्लिकेशन डेवलपमेंट लाइफ साइकिल में यूनिट टेस्ट कौन लिखता है?",opts:["सिस्टम एडमिनिस्ट्रेटर","प्रोजेक्ट स्पॉन्सर","सॉफ्टवेयर डेवलपर","तकनीकी लेखक"],ans:2,exp:"सॉफ्टवेयर डेवलपर आम तौर पर यूनिट टेस्ट लिखने और निष्पादित करने के लिए जिम्मेदार होते हैं। यूनिट टेस्ट कोड के एक विशिष्ट खंड की कार्यक्षमता को सत्यापित करते हैं। यह विकास चक्र के आरंभ में ही बग को पकड़ लेता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following is considered a Community Cloud?",opts:["A cloud infrastructure shared by several organizations with shared concerns","A cloud available to the general public","A cloud owned by a single company","A cloud built for local community gaming"],ans:0,exp:"A Community Cloud is an infrastructure shared by several organizations that have specific shared concerns (e.g., security, compliance, jurisdiction). It may be managed by the organizations or a third party. It distributes costs among fewer users than a public cloud."},hi:{q:"निम्नलिखित में से किसे कम्युनिटी क्लाउड माना जाता है?",opts:["साझा चिंताओं वाले कई संगठनों द्वारा साझा किया गया क्लाउड इंफ्रास्ट्रक्चर","आम जनता के लिए उपलब्ध एक क्लाउड","एकल कंपनी के स्वामित्व वाला क्लाउड","स्थानीय कम्युनिटी गेमिंग के लिए बनाया गया क्लाउड"],ans:0,exp:"कम्युनिटी क्लाउड कई संगठनों द्वारा साझा किया गया एक बुनियादी ढांचा है जिनकी विशिष्ट साझा चिंताएं (जैसे, सुरक्षा, अनुपालन) हैं। इसका प्रबंधन संगठनों या किसी तीसरे पक्ष द्वारा किया जा सकता है। यह पब्लिक क्लाउड की तुलना में कम उपयोगकर्ताओं के बीच लागत वितरित करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is 'Prototyping' in SDLC?",opts:["Writing the final production code","Creating an incomplete, preliminary version of the application","Deploying the app to live servers","Deleting old code"],ans:1,exp:"Prototyping involves creating a working model of the software with limited functionality to demonstrate the concept to stakeholders. It helps gather early feedback before heavy coding begins. Prototypes are often discarded or refined into the final product."},hi:{q:"SDLC में 'प्रोटोटाइपिंग' क्या है?",opts:["अंतिम उत्पादन कोड लिखना","एप्लिकेशन का एक अपूर्ण, प्रारंभिक संस्करण बनाना","ऐप को लाइव सर्वर पर तैनात करना","पुराने कोड को हटाना"],ans:1,exp:"प्रोटोटाइपिंग में हितधारकों को अवधारणा प्रदर्शित करने के लिए सीमित कार्यक्षमता वाले सॉफ़्टवेयर का एक कार्यशील मॉडल बनाना शामिल है। यह भारी कोडिंग शुरू होने से पहले प्रारंभिक प्रतिक्रिया इकट्ठा करने में मदद करता है। प्रोटोटाइप को अक्सर अंतिम उत्पाद में परिष्कृत किया जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following acts as a hypervisor to create virtual machines?",opts:["VMware ESXi","Google Chrome","Microsoft Word","Adobe Reader"],ans:0,exp:"VMware ESXi is an enterprise-class, type-1 hypervisor developed by VMware for deploying and serving virtual computers. It runs directly on the host machine's hardware to manage guest operating systems. It is foundational to IaaS implementations."},hi:{q:"वर्चुअल मशीन बनाने के लिए निम्नलिखित में से कौन हाइपरवाइज़र के रूप में कार्य करता है?",opts:["VMware ESXi","Google Chrome","Microsoft Word","Adobe Reader"],ans:0,exp:"VMware ESXi एक एंटरप्राइज़-क्लास हाइपरवाइज़र है जो वर्चुअल कंप्यूटरों को तैनात करने के लिए विकसित किया गया है। यह अतिथि ऑपरेटिंग सिस्टम को प्रबंधित करने के लिए सीधे होस्ट मशीन के हार्डवेयर पर चलता है। यह IaaS के लिए आधारभूत है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the primary purpose of a Feasibility Study in SDLC?",opts:["To write database queries","To assess if the project is technically and financially viable","To design the user interface","To train the end users"],ans:1,exp:"The Feasibility Study determines whether the project should go forward by analyzing technical, economic, legal, operational, and scheduling factors. It prevents organizations from investing in unviable projects. It culminates in a feasibility report."},hi:{q:"SDLC में व्यवहार्यता अध्ययन (Feasibility Study) का प्राथमिक उद्देश्य क्या है?",opts:["डेटाबेस क्वेरी लिखने के लिए","यह आकलन करने के लिए कि क्या परियोजना तकनीकी और वित्तीय रूप से व्यवहार्य है","यूजर इंटरफेस डिजाइन करने के लिए","अंतिम उपयोगकर्ताओं को प्रशिक्षित करने के लिए"],ans:1,exp:"व्यवहार्यता अध्ययन तकनीकी, आर्थिक और परिचालन कारकों का विश्लेषण करके यह निर्धारित करता है कि परियोजना को आगे बढ़ना चाहिए या नहीं। यह संगठनों को अव्यवहार्य परियोजनाओं में निवेश करने से रोकता है। यह एक रिपोर्ट में समाप्त होता है।"}},
{type:"mcq",diff:"medium",en:{q:"In cloud security, what does the 'Shared Responsibility Model' imply?",opts:["The cloud provider is solely responsible for all security","The customer is solely responsible for all security","Security duties are divided between the cloud provider and the customer","Security is shared with third-party hackers"],ans:2,exp:"The Shared Responsibility Model states that cloud providers are responsible for securing the underlying infrastructure (security OF the cloud), while customers are responsible for securing their data and configurations (security IN the cloud). This varies by service model (IaaS, PaaS, SaaS)."},hi:{q:"क्लाउड सुरक्षा में, 'साझा जिम्मेदारी मॉडल' (Shared Responsibility Model) का क्या अर्थ है?",opts:["क्लाउड प्रदाता पूरी तरह से सभी सुरक्षा के लिए जिम्मेदार है","ग्राहक पूरी तरह से सभी सुरक्षा के लिए जिम्मेदार है","सुरक्षा कर्तव्यों को क्लाउड प्रदाता और ग्राहक के बीच विभाजित किया गया है","सुरक्षा तीसरे पक्ष के हैकर्स के साथ साझा की जाती है"],ans:2,exp:"साझा जिम्मेदारी मॉडल कहता है कि क्लाउड प्रदाता अंतर्निहित बुनियादी ढांचे (क्लाउड की सुरक्षा) को सुरक्षित करने के लिए जिम्मेदार हैं, जबकि ग्राहक अपने डेटा (क्लाउड में सुरक्षा) को सुरक्षित करने के लिए जिम्मेदार हैं। यह सेवा मॉडल द्वारा भिन्न होता है।"}},
{type:"mcq",diff:"medium",en:{q:"What document describes the step-by-step instructions a tester follows to verify a specific software feature?",opts:["Test Case","Project Charter","Source Code","Deployment Plan"],ans:0,exp:"A Test Case outlines the prerequisites, inputs, execution steps, and expected results to verify a particular functionality of the software. Testers follow it rigorously during the testing phase. It ensures systematic and repeatable testing."},hi:{q:"कौन सा दस्तावेज़ उन चरण-दर-चरण निर्देशों का वर्णन करता है जिनका एक टेस्टर एक विशिष्ट सॉफ़्टवेयर सुविधा को सत्यापित करने के लिए पालन करता है?",opts:["टेस्ट केस","प्रोजेक्ट चार्टर","सोर्स कोड","डिप्लॉयमेंट प्लान"],ans:0,exp:"एक टेस्ट केस सॉफ्टवेयर की किसी विशेष कार्यक्षमता को सत्यापित करने के लिए आवश्यक शर्तें, इनपुट, निष्पादन चरण और अपेक्षित परिणाम की रूपरेखा तैयार करता है। परीक्षण चरण के दौरान टेस्टर इसका कड़ाई से पालन करते हैं। यह व्यवस्थित परीक्षण सुनिश्चित करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is 'Serverless Computing'?",opts:["Computing without any backend servers","A model where the cloud provider dynamically manages the allocation of machine resources","Using only local desktop computers","A network without routers"],ans:1,exp:"Serverless computing is an execution model where the cloud provider automatically provisions, scales, and manages the infrastructure required to run code. Developers write functions, and the provider handles the servers entirely. Pricing is based on actual execution time."},hi:{q:"'सर्वरलेस कंप्यूटिंग' क्या है?",opts:["बिना किसी बैकएंड सर्वर के कंप्यूटिंग","एक मॉडल जहां क्लाउड प्रदाता मशीन संसाधनों के आवंटन का प्रबंधन करता है","केवल स्थानीय डेस्कटॉप कंप्यूटर का उपयोग करना","राउटर के बिना एक नेटवर्क"],ans:1,exp:"सर्वरलेस कंप्यूटिंग एक निष्पादन मॉडल है जहां क्लाउड प्रदाता कोड चलाने के लिए आवश्यक बुनियादी ढांचे को स्वचालित रूप से प्रबंधित करता है। डेवलपर्स फ़ंक्शन लिखते हैं, और प्रदाता पूरी तरह से सर्वर को संभालता है। मूल्य निर्धारण वास्तविक निष्पादन समय पर आधारित है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following is a Version Control System used heavily in application development?",opts:["Git","Adobe Photoshop","Microsoft Excel","Apache Server"],ans:0,exp:"Git is a distributed version control system used by developers to track changes in source code during software development. It allows multiple developers to collaborate without overwriting each other's work. It is essential in modern SDLC practices."},hi:{q:"एप्लिकेशन विकास में भारी रूप से उपयोग किया जाने वाला संस्करण नियंत्रण प्रणाली (Version Control System) कौन सा है?",opts:["Git","Adobe Photoshop","Microsoft Excel","Apache Server"],ans:0,exp:"Git एक वितरित संस्करण नियंत्रण प्रणाली है जिसका उपयोग डेवलपर्स द्वारा सॉफ्टवेयर विकास के दौरान स्रोत कोड में परिवर्तनों को ट्रैक करने के लिए किया जाता है। यह कई डेवलपर्स को एक साथ काम करने की अनुमति देता है। यह आधुनिक SDLC प्रथाओं में आवश्यक है।"}},
{type:"mcq",diff:"medium",en:{q:"What is Data as a Service (DaaS)?",opts:["Software downloaded locally","Data management strategy that uses the cloud to deliver data storage, integration, and processing services","Desktop virtualization","A form of hardware leasing"],ans:1,exp:"Data as a Service (DaaS) provides data on demand to users regardless of their geographic location. It relies on cloud computing to deliver storage, processing, and analytics services. It allows companies to handle massive datasets efficiently."},hi:{q:"डेटा ऐज़ ए सर्विस (DaaS) क्या है?",opts:["स्थानीय रूप से डाउनलोड किया गया सॉफ्टवेयर","डेटा प्रबंधन रणनीति जो डेटा भंडारण, एकीकरण और प्रसंस्करण सेवाएं प्रदान करने के लिए क्लाउड का उपयोग करती है","डेस्कटॉप वर्चुअलाइजेशन","हार्डवेयर लीजिंग का एक रूप"],ans:1,exp:"डेटा ऐज़ ए सर्विस (DaaS) उपयोगकर्ताओं को उनके भौगोलिक स्थान की परवाह किए बिना मांग पर डेटा प्रदान करता है। यह भंडारण, प्रसंस्करण और विश्लेषण सेवाएं प्रदान करने के लिए क्लाउड कंप्यूटिंग पर निर्भर करता है। यह विशाल डेटासेट को संभालने की अनुमति देता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which phase of the SDLC involves checking if the software behaves correctly under heavy load?",opts:["Requirements Gathering","Performance Testing","System Design","Maintenance"],ans:1,exp:"Performance Testing is a specific testing type within the Testing phase. It evaluates how the system performs in terms of responsiveness and stability under a particular workload. It ensures the application won't crash during peak usage."},hi:{q:"SDLC के किस चरण में यह जांचना शामिल है कि क्या सॉफ्टवेयर भारी भार के तहत सही ढंग से व्यवहार करता है?",opts:["आवश्यकताओं को इकट्ठा करना","प्रदर्शन परीक्षण (Performance Testing)","सिस्टम डिजाइन","रखरखाव"],ans:1,exp:"प्रदर्शन परीक्षण परीक्षण चरण के भीतर एक विशिष्ट परीक्षण प्रकार है। यह मूल्यांकन करता है कि एक विशेष कार्यभार के तहत प्रतिक्रिया और स्थिरता के मामले में सिस्टम कैसा प्रदर्शन करता है। यह सुनिश्चित करता है कि चरम उपयोग के दौरान एप्लिकेशन क्रैश न हो।"}},
{type:"mcq",diff:"medium",en:{q:"What is a major characteristic of an SLA (Service Level Agreement) in cloud computing?",opts:["It outlines the hardware brands used","It guarantees a certain level of uptime and performance from the cloud provider","It dictates the programming language used","It is an employment contract"],ans:1,exp:"An SLA is a formal contract between a service provider and the customer that defines the level of service expected. It typically guarantees aspects like 99.9% uptime, support responsiveness, and penalties for failing to meet these metrics. It is crucial for enterprise cloud adoption."},hi:{q:"क्लाउड कंप्यूटिंग में SLA (सर्विस लेवल एग्रीमेंट) की प्रमुख विशेषता क्या है?",opts:["यह प्रयुक्त हार्डवेयर ब्रांडों की रूपरेखा तैयार करता है","यह क्लाउड प्रदाता से अपटाइम और प्रदर्शन के एक निश्चित स्तर की गारंटी देता है","यह प्रयुक्त प्रोग्रामिंग भाषा को निर्धारित करता है","यह एक रोजगार अनुबंध है"],ans:1,exp:"SLA एक सेवा प्रदाता और ग्राहक के बीच एक औपचारिक अनुबंध है जो अपेक्षित सेवा के स्तर को परिभाषित करता है। यह आम तौर पर 99.9% अपटाइम, समर्थन और इन मीट्रिक को पूरा करने में विफल रहने पर दंड की गारंटी देता है। यह उद्यम क्लाउड अपनाने के लिए महत्वपूर्ण है।"}},
{type:"mcq",diff:"medium",en:{q:"In software development, what does 'UI/UX' stand for?",opts:["Universal Integration / Universal Execution","User Interface / User Experience","User Identification / User Exchange","Unified Internet / Unified X-ray"],ans:1,exp:"UI stands for User Interface, which encompasses the visual elements users interact with. UX stands for User Experience, which relates to the overall feel and usability of the application. Designing a good UI/UX is critical in the Design phase of SDLC."},hi:{q:"सॉफ्टवेयर विकास में, 'UI/UX' का क्या अर्थ है?",opts:["यूनिवर्सल इंटीग्रेशन / यूनिवर्सल एक्ज़ीक्यूशन","यूजर इंटरफेस / यूजर एक्सपीरियंस","यूजर आइडेंटिफिकेशन / यूजर एक्सचेंज","यूनिफाइड इंटरनेट / यूनिफाइड एक्स-रे"],ans:1,exp:"UI का अर्थ यूजर इंटरफेस है, जिसमें वे दृश्य तत्व शामिल हैं जिनके साथ उपयोगकर्ता बातचीत करते हैं। UX का अर्थ यूजर एक्सपीरियंस है, जो एप्लिकेशन की समग्र उपयोगिता से संबंधित है। SDLC के डिज़ाइन चरण में एक अच्छा UI/UX डिज़ाइन करना महत्वपूर्ण है।"}},
{type:"mcq",diff:"medium",en:{q:"Which concept ensures that a cloud provider runs identical infrastructure in distinct geographic regions to survive regional disasters?",opts:["Geo-Redundancy","Multitenancy","Elasticity","Vendor Lock-in"],ans:0,exp:"Geo-Redundancy involves replicating data and infrastructure across multiple geographically separated data centers. If a hurricane or power outage destroys one region, the system fails over to another region automatically. This guarantees business continuity."},hi:{q:"कौन सी अवधारणा यह सुनिश्चित करती है कि क्लाउड प्रदाता क्षेत्रीय आपदाओं से बचने के लिए अलग-अलग भौगोलिक क्षेत्रों में समान बुनियादी ढांचा चलाता है?",opts:["जियो-रिडंडेंसी","मल्टीटेनेंसी","इलास्टिसिटी","वेंडर लॉक-इन"],ans:0,exp:"जियो-रिडंडेंसी में कई भौगोलिक रूप से अलग किए गए डेटा केंद्रों में डेटा और बुनियादी ढांचे की नकल करना शामिल है। यदि कोई आपदा एक क्षेत्र को नष्ट कर देती है, तो सिस्टम स्वचालित रूप से दूसरे क्षेत्र में चला जाता है। यह व्यापार निरंतरता की गारंटी देता है।"}},
{type:"mcq",diff:"medium",en:{q:"Who usually manages the CI/CD pipeline in a modern development team?",opts:["Business Analyst","DevOps Engineer","Sales Manager","Content Writer"],ans:1,exp:"A DevOps Engineer bridges development and IT operations. They manage the Continuous Integration and Continuous Deployment (CI/CD) pipelines to automate the building, testing, and deployment of applications. This speeds up the software release lifecycle."},hi:{q:"आधुनिक विकास दल में आमतौर पर CI/CD पाइपलाइन का प्रबंधन कौन करता है?",opts:["व्यापार विश्लेषक","डेवऑप्स (DevOps) इंजीनियर","बिक्री प्रबंधक","सामग्री लेखक"],ans:1,exp:"एक DevOps इंजीनियर विकास और IT संचालन को जोड़ता है। वे अनुप्रयोगों के निर्माण, परीक्षण और तैनाती को स्वचालित करने के लिए सतत एकीकरण (CI/CD) पाइपलाइनों का प्रबंधन करते हैं। यह सॉफ्टवेयर रिलीज जीवनचक्र को गति देता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of these is a typical database management system used as backend in web apps?",opts:["MySQL","HTML","CSS","Photoshop"],ans:0,exp:"MySQL is a widely used open-source relational database management system. It is commonly used as the backend database for web applications to store user data securely. Developers interact with it using SQL queries during the Implementation phase."},hi:{q:"वेब ऐप में बैकएंड के रूप में उपयोग की जाने वाली एक विशिष्ट डेटाबेस प्रबंधन प्रणाली कौन सी है?",opts:["MySQL","HTML","CSS","Photoshop"],ans:0,exp:"MySQL एक व्यापक रूप से उपयोग किया जाने वाला ओपन-सोर्स रिलेशनल डेटाबेस प्रबंधन सिस्टम है। उपयोगकर्ता डेटा को सुरक्षित रूप से संग्रहीत करने के लिए वेब अनुप्रयोगों के लिए बैकएंड डेटाबेस के रूप में इसका उपयोग किया जाता है। डेवलपर्स SQL प्रश्नों का उपयोग करके इसके साथ बातचीत करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"What is 'Data Migration' in the context of system deployment?",opts:["Translating code from Java to Python","Moving existing data from an old system to the newly developed system","Backing up data to a floppy disk","Deleting old logs"],ans:1,exp:"Data Migration is the process of transferring data from legacy systems to a new system. It often involves extracting, transforming, and loading (ETL) the data to match the new database schema. This is a critical step during the Deployment phase."},hi:{q:"सिस्टम डिप्लॉयमेंट के संदर्भ में 'डेटा माइग्रेशन' क्या है?",opts:["जावा से पायथन में कोड का अनुवाद करना","मौजूदा डेटा को पुराने सिस्टम से नए विकसित सिस्टम में ले जाना","फ्लॉपी डिस्क पर डेटा का बैकअप लेना","पुराने लॉग हटाना"],ans:1,exp:"डेटा माइग्रेशन पुराने सिस्टम से नए सिस्टम में डेटा स्थानांतरित करने की प्रक्रिया है। नए डेटाबेस स्कीमा से मेल खाने के लिए इसमें अक्सर डेटा निकालना और लोड करना (ETL) शामिल होता है। यह डिप्लॉयमेंट चरण के दौरान एक महत्वपूर्ण कदम है।"}},
{type:"tf",diff:"medium",en:{q:"In the PaaS model, the customer is responsible for managing the underlying server hardware and operating system.",opts:["True","False"],ans:1,exp:"False. In Platform as a Service (PaaS), the cloud provider manages the underlying infrastructure, including hardware, operating systems, and networking. The customer is only responsible for managing their applications and data."},hi:{q:"PaaS मॉडल में, ग्राहक अंतर्निहित सर्वर हार्डवेयर और ऑपरेटिंग सिस्टम के प्रबंधन के लिए जिम्मेदार है।",opts:["सही","गलत"],ans:1,exp:"गलत। प्लेटफ़ॉर्म ऐज़ ए सर्विस (PaaS) में, क्लाउड प्रदाता हार्डवेयर, ओएस और नेटवर्किंग सहित अंतर्निहित बुनियादी ढांचे का प्रबंधन करता है। ग्राहक केवल अपने एप्लिकेशन और डेटा के प्रबंधन के लिए जिम्मेदार है।"}},
{type:"tf",diff:"medium",en:{q:"White-box testing is a technique where the tester has access to the internal source code.",opts:["True","False"],ans:0,exp:"True. White-box testing (or clear-box testing) is a software testing method in which the internal structure, design, and implementation of the item being tested are known to the tester. It is usually performed by developers."},hi:{q:"व्हाइट-बॉक्स परीक्षण एक ऐसी तकनीक है जहाँ टेस्टर की आंतरिक स्रोत कोड तक पहुंच होती है।",opts:["सही","गलत"],ans:0,exp:"सही। व्हाइट-बॉक्स परीक्षण एक सॉफ़्टवेयर परीक्षण विधि है जिसमें परीक्षण किए जा रहे आइटम की आंतरिक संरचना, डिज़ाइन और कार्यान्वयन टेस्टर को ज्ञात होते हैं। यह आमतौर पर डेवलपर्स द्वारा किया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which of the following technologies is fundamental to implementing Cloud Computing data centers?",opts:["Compiler technology","Virtualization","Analog signal processing","Local Area Network switches only"],ans:1,exp:"Virtualization is the foundational technology of cloud computing. It allows multiple virtual machines, each with its own OS, to run on a single physical server. This abstracts the hardware and enables the resource pooling and elasticity of the cloud."},hi:{q:"क्लाउड कंप्यूटिंग डेटा केंद्रों को लागू करने के लिए निम्नलिखित में से कौन सी तकनीक मौलिक है?",opts:["कंपाइलर प्रौद्योगिकी","वर्चुअलाइजेशन (Virtualization)","एनालॉग सिग्नल प्रोसेसिंग","केवल लोकल एरिया नेटवर्क स्विच"],ans:1,exp:"वर्चुअलाइजेशन क्लाउड कंप्यूटिंग की आधारभूत तकनीक है। यह कई वर्चुअल मशीनों को एकल भौतिक सर्वर पर चलाने की अनुमति देता है। यह हार्डवेयर को अमूर्त करता है और क्लाउड के संसाधन पूलिंग और लोच को सक्षम बनाता है।"}},
{type:"mcq",diff:"hard",en:{q:"In Agile SDLC methodology, what is a 'Sprint'?",opts:["A fast internet connection","A set period of time during which specific work has to be completed and made ready for review","A type of database query","A security breach"],ans:1,exp:"In Agile development, a Sprint is a time-boxed iteration, usually lasting 1-4 weeks, where a cross-functional team works to complete a specific set of deliverables. At the end of the sprint, a potentially shippable product increment is reviewed."},hi:{q:"एजाइल SDLC कार्यप्रणाली में, 'स्प्रिंट' (Sprint) क्या है?",opts:["एक तेज़ इंटरनेट कनेक्शन","एक निर्धारित समय जिसके दौरान विशिष्ट कार्य पूरा किया जाना है और समीक्षा के लिए तैयार किया जाना है","एक प्रकार का डेटाबेस क्वेरी","सुरक्षा में सेंध"],ans:1,exp:"एजाइल विकास में, एक स्प्रिंट एक समय-बद्ध पुनरावृत्ति है, जो आमतौर पर 1-4 सप्ताह तक चलती है, जहां एक क्रॉस-फ़ंक्शनल टीम विशिष्ट डिलिवरेबल्स को पूरा करने के लिए काम करती है। स्प्रिंट के अंत में, एक समीक्षा की जाती है।"}},
{type:"mcq",diff:"hard",en:{q:"What is 'VPC' in AWS cloud computing?",opts:["Virtual Private Cloud","Virtual Public Computer","Visual Processing Cloud","Variable Power Consumption"],ans:0,exp:"A Virtual Private Cloud (VPC) is a secure, isolated private cloud hosted within a public cloud. It enables users to launch AWS resources into a virtual network that they have defined, providing advanced networking and security control."},hi:{q:"AWS क्लाउड कंप्यूटिंग में 'VPC' क्या है?",opts:["वर्चुअल प्राइवेट क्लाउड","वर्चुअल पब्लिक कंप्यूटर","विज़ुअल प्रोसेसिंग क्लाउड","वेरिएबल पावर कंजम्पशन"],ans:0,exp:"वर्चुअल प्राइवेट क्लाउड (VPC) एक सार्वजनिक क्लाउड के भीतर होस्ट किया गया एक सुरक्षित, अलग निजी क्लाउड है। यह उपयोगकर्ताओं को AWS संसाधनों को एक आभासी नेटवर्क में लॉन्च करने में सक्षम बनाता है जिसे उन्होंने परिभाषित किया है।"}},
{type:"mcq",diff:"hard",en:{q:"What describes the 'Microservices' architecture in application development?",opts:["An application structured as a single massive executable","An application structured as a collection of small, autonomous, and loosely coupled services","Developing applications for micro-computers","Using Microsoft services exclusively"],ans:1,exp:"Microservices architecture structures an application as a collection of small, independently deployable services that communicate over a network via APIs. This approach highly complements cloud environments by allowing individual components to scale independently."},hi:{q:"एप्लिकेशन विकास में 'माइक्रोसर्विसेज' आर्किटेक्चर का क्या वर्णन है?",opts:["एकल बड़े निष्पादन योग्य के रूप में संरचित एप्लिकेशन","छोटे, स्वायत्त और शिथिल युग्मित सेवाओं के संग्रह के रूप में संरचित एक एप्लिकेशन","माइक्रो-कंप्यूटर के लिए एप्लिकेशन विकसित करना","विशेष रूप से माइक्रोसॉफ्ट सेवाओं का उपयोग करना"],ans:1,exp:"माइक्रोसर्विसेज आर्किटेक्चर एक एप्लिकेशन को छोटी, स्वतंत्र रूप से तैनात करने योग्य सेवाओं के संग्रह के रूप में तैयार करता है जो एपीआई के माध्यम से नेटवर्क पर संवाद करते हैं। यह क्लाउड वातावरण का अत्यधिक पूरक है।"}},
{type:"mcq",diff:"hard",en:{q:"Which of the following is a NoSQL database often used in modern cloud apps?",opts:["Oracle SQL","Microsoft SQL Server","MongoDB (Wait, MongoDB is NoSQL) Let's use PostgreSQL as wrong. Correct: MongoDB","PostgreSQL"],ans:2,exp:"MongoDB is a popular NoSQL document-oriented database. Unlike traditional SQL relational databases, NoSQL databases handle unstructured data easily and scale horizontally, making them ideal for modern, cloud-native web applications."},hi:{q:"निम्नलिखित में से कौन सा NoSQL डेटाबेस है जिसका उपयोग अक्सर आधुनिक क्लाउड ऐप में किया जाता है?",opts:["Oracle SQL","Microsoft SQL Server","MongoDB","PostgreSQL"],ans:2,exp:"MongoDB एक लोकप्रिय NoSQL दस्तावेज़-उन्मुख डेटाबेस है। पारंपरिक SQL रिलेशनल डेटाबेस के विपरीत, NoSQL डेटाबेस असंरचित डेटा को आसानी से संभालते हैं और क्षैतिज रूप से स्केल करते हैं, जो उन्हें आधुनिक क्लाउड ऐप के लिए आदर्श बनाते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"In SDLC, what is 'Technical Debt'?",opts:["The money owed to programmers","The implied cost of additional rework caused by choosing an easy solution now instead of a better approach","The cost of buying servers","A loan taken from a bank for IT infrastructure"],ans:1,exp:"Technical debt reflects the extra development work that arises when code that is easy to implement in the short run is used instead of applying the best overall solution. If not refactored, technical debt accumulates and slows down future development."},hi:{q:"SDLC में 'टेक्निकल डेब्ट' (Technical Debt) क्या है?",opts:["प्रोग्रामरों का बकाया पैसा","बेहतर दृष्टिकोण के बजाय अब आसान समाधान चुनने के कारण अतिरिक्त काम की निहित लागत","सर्वर खरीदने की लागत","आईटी इंफ्रास्ट्रक्चर के लिए बैंक से लिया गया कर्ज"],ans:1,exp:"टेक्निकल डेब्ट उस अतिरिक्त विकास कार्य को दर्शाता है जो तब उत्पन्न होता है जब अल्पावधि में लागू करने में आसान कोड का उपयोग किया जाता है। यदि इसे ठीक नहीं किया जाता है, तो तकनीकी ऋण जमा हो जाता है और भविष्य के विकास को धीमा कर देता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which cloud security concept involves scrambling data so it cannot be read without a key?",opts:["Firewall","Load Balancing","Encryption","VPC Peering"],ans:2,exp:"Encryption is the process of converting readable data into an unreadable encoded format. It protects sensitive data stored in the cloud (data at rest) and data traveling across the internet (data in transit). A decryption key is required to read it."},hi:{q:"किस क्लाउड सुरक्षा अवधारणा में डेटा को स्क्रैम्बल करना शामिल है ताकि इसे कुंजी के बिना पढ़ा न जा सके?",opts:["फ़ायरवॉल","लोड बैलेंसिंग","एन्क्रिप्शन","VPC पीयरिंग"],ans:2,exp:"एन्क्रिप्शन पठनीय डेटा को अपठनीय एन्कोडेड प्रारूप में परिवर्तित करने की प्रक्रिया है। यह क्लाउड में संग्रहीत संवेदनशील डेटा और इंटरनेट पर यात्रा करने वाले डेटा की सुरक्षा करता है। इसे पढ़ने के लिए डिक्रिप्शन कुंजी की आवश्यकता होती है।"}},
{type:"mcq",diff:"hard",en:{q:"What does an API API Gateway do in a cloud-native application?",opts:["It acts as a reverse proxy to accept all API calls, aggregate the various services required, and return the appropriate result","It blocks all incoming traffic","It is a physical router","It creates graphical user interfaces"],ans:0,exp:"An API Gateway serves as a single entry point into a system of microservices. It handles requests by routing them to the appropriate backend service, enforcing security policies, and managing traffic loads. It simplifies the client interface."},hi:{q:"क्लाउड-नेटिव एप्लिकेशन में API गेटवे क्या करता है?",opts:["यह सभी एपीआई कॉल स्वीकार करने, आवश्यक विभिन्न सेवाओं को एकत्र करने और उपयुक्त परिणाम वापस करने के लिए रिवर्स प्रॉक्सी के रूप में कार्य करता है","यह सभी आने वाले ट्रैफिक को ब्लॉक करता है","यह एक भौतिक राउटर है","यह ग्राफिकल यूजर इंटरफेस बनाता है"],ans:0,exp:"एक एपीआई गेटवे माइक्रोसर्विसेज की प्रणाली में एक एकल प्रवेश बिंदु के रूप में कार्य करता है। यह उचित बैकएंड सेवा को रूट करके, सुरक्षा नीतियों को लागू करके अनुरोधों को संभालता है। यह क्लाइंट इंटरफ़ेस को सरल बनाता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which testing type evaluates how an application interacts with other hardware or software systems?",opts:["Unit Testing","Integration Testing","Usability Testing","A/B Testing"],ans:1,exp:"Integration Testing is performed to expose defects in the interfaces and interactions between integrated components or systems. After unit testing individual modules, developers combine them and perform integration testing to ensure they work together flawlessly."},hi:{q:"कौन सा परीक्षण प्रकार मूल्यांकन करता है कि एप्लिकेशन अन्य हार्डवेयर या सॉफ़्टवेयर सिस्टम के साथ कैसे संपर्क करता है?",opts:["यूनिट परीक्षण","इंटीग्रेशन परीक्षण (Integration Testing)","प्रयोज्य परीक्षण","ए/बी परीक्षण"],ans:1,exp:"इंटीग्रेशन परीक्षण एकीकृत घटकों या प्रणालियों के बीच इंटरफेस और इंटरैक्शन में दोषों को उजागर करने के लिए किया जाता है। व्यक्तिगत मॉड्यूल का परीक्षण करने के बाद, डेवलपर्स यह सुनिश्चित करने के लिए उन्हें जोड़ते हैं कि वे एक साथ काम करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"What is 'Continuous Integration' (CI) in software development?",opts:["Continuously paying server bills","The practice of merging all developer working copies to a shared mainline several times a day","A method to constantly crash servers","Writing code without stopping"],ans:1,exp:"Continuous Integration is a DevOps software development practice where developers regularly merge their code changes into a central repository. Automated builds and tests are run after each merge. It helps detect integration bugs quickly and improves quality."},hi:{q:"सॉफ्टवेयर विकास में 'सतत एकीकरण' (Continuous Integration) क्या है?",opts:["लगातार सर्वर बिलों का भुगतान","सभी डेवलपर वर्किंग प्रतियों को दिन में कई बार साझा मेनलाइन में विलय करने की प्रथा","सर्वर को लगातार क्रैश करने की एक विधि","बिना रुके कोड लिखना"],ans:1,exp:"सतत एकीकरण एक DevOps अभ्यास है जहां डेवलपर्स नियमित रूप से अपने कोड परिवर्तनों को एक केंद्रीय रिपॉजिटरी में विलय करते हैं। प्रत्येक मर्ज के बाद स्वचालित बिल्ड और परीक्षण चलाए जाते हैं। यह एकीकरण बग का जल्दी पता लगाने में मदद करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which computing model extends cloud computing to the edge of an enterprise's network?",opts:["Quantum Computing","Fog Computing","Grid Computing","Mainframe Computing"],ans:1,exp:"Fog Computing (or Edge Computing) pushes cloud computing capabilities to the edge of the network, closer to the devices generating data. This reduces latency and bandwidth use for applications like IoT and autonomous vehicles by processing data locally."},hi:{q:"कौन सा कंप्यूटिंग मॉडल क्लाउड कंप्यूटिंग को उद्यम के नेटवर्क के किनारे तक बढ़ाता है?",opts:["क्वांटम कंप्यूटिंग","फॉग कंप्यूटिंग (Fog Computing)","ग्रिड कंप्यूटिंग","मेनफ्रेम कंप्यूटिंग"],ans:1,exp:"फॉग कंप्यूटिंग क्लाउड कंप्यूटिंग क्षमताओं को नेटवर्क के किनारे, डेटा उत्पन्न करने वाले उपकरणों के करीब धकेलता है। यह डेटा को स्थानीय रूप से संसाधित करके IoT जैसे अनुप्रयोगों के लिए विलंबता और बैंडविड्थ उपयोग को कम करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In object-oriented application development, what does 'Encapsulation' mean?",opts:["Compressing files to a zip archive","Binding the data and the functions that manipulate them together in a single unit","Uploading code to the cloud","Drawing UML diagrams"],ans:1,exp:"Encapsulation is an OOP concept that binds together the data (variables) and the code acting on the data (methods) into a single unit, usually a class. It restricts direct access to some of an object's components, ensuring data hiding and security."},hi:{q:"ऑब्जेक्ट-ओरिएंटेड एप्लिकेशन विकास में, 'एनकैप्सुलेशन' का क्या अर्थ है?",opts:["फ़ाइलों को ज़िप संग्रह में संपीड़ित करना","डेटा और उन कार्यों को बांधना जो उन्हें एक इकाई में हेरफेर करते हैं","क्लाउड पर कोड अपलोड करना","यूएमएल आरेख खींचना"],ans:1,exp:"एनकैप्सुलेशन एक OOP अवधारणा है जो डेटा (चर) और डेटा (विधियों) पर कार्य करने वाले कोड को एक इकाई में बांधती है। यह किसी ऑब्जेक्ट के कुछ घटकों तक सीधी पहुंच को प्रतिबंधित करता है, जिससे डेटा छिपता है।"}},
{type:"mcq",diff:"hard",en:{q:"What does the CAP theorem state regarding distributed data stores in the cloud?",opts:["A system can only provide two of three guarantees: Consistency, Availability, and Partition tolerance","Cloud Applications Provide everything","Consistency is Always Perfect","Partitioning ruins databases"],ans:0,exp:"The CAP theorem states that it is impossible for a distributed data store to simultaneously provide more than two out of three guarantees: Consistency, Availability, and Partition tolerance. Architects must choose which two to prioritize when designing cloud databases."},hi:{q:"क्लाउड में वितरित डेटा स्टोर के संबंध में CAP प्रमेय (theorem) क्या कहता है?",opts:["एक प्रणाली तीन गारंटी में से केवल दो प्रदान कर सकती है: स्थिरता, उपलब्धता और विभाजन सहिष्णुता","क्लाउड एप्लीकेशन सब कुछ प्रदान करते हैं","स्थिरता हमेशा परिपूर्ण होती है","विभाजन डेटाबेस को बर्बाद कर देता है"],ans:0,exp:"CAP प्रमेय बताता है कि एक वितरित डेटा स्टोर के लिए एक साथ तीन में से दो से अधिक गारंटी प्रदान करना असंभव है: स्थिरता, उपलब्धता और विभाजन सहिष्णुता। क्लाउड डेटाबेस डिजाइन करते समय आर्किटेक्ट्स को यह चुनना होगा कि किन दो को प्राथमिकता दी जाए।"}},
{type:"mcq",diff:"hard",en:{q:"Which document is used to log and track software defects discovered during the Testing phase?",opts:["Requirements Matrix","Bug Tracking Report / Issue Log","Source Code Repo","User Guide"],ans:1,exp:"A Bug Tracking Report or Issue Log is a vital document in SDLC where testers record details of software defects. It includes the bug's severity, steps to reproduce, and status. Developers use this log to understand and fix the identified problems."},hi:{q:"परीक्षण चरण के दौरान खोजे गए सॉफ़्टवेयर दोषों को लॉग और ट्रैक करने के लिए किस दस्तावेज़ का उपयोग किया जाता है?",opts:["आवश्यकता मैट्रिक्स","बग ट्रैकिंग रिपोर्ट / इश्यू लॉग","सोर्स कोड रेपो","उपयोगकर्ता गाइड"],ans:1,exp:"बग ट्रैकिंग रिपोर्ट SDLC में एक महत्वपूर्ण दस्तावेज़ है जहाँ परीक्षक सॉफ़्टवेयर दोषों का विवरण दर्ज करते हैं। इसमें बग की गंभीरता, पुनरुत्पादन के चरण और स्थिति शामिल है। डेवलपर्स इस लॉग का उपयोग पहचानी गई समस्याओं को ठीक करने के लिए करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"What is 'Blue/Green Deployment' in cloud application updates?",opts:["Changing the CSS colors of the application","A release technique that reduces downtime and risk by running two identical production environments","Deploying servers in the ocean and forest","Recycling old servers"],ans:1,exp:"Blue/Green deployment is a technique that involves running two identical production environments (Blue and Green). Only one serves live traffic at a time. New code is deployed to the idle environment, tested, and then traffic is switched, resulting in zero downtime."},hi:{q:"क्लाउड एप्लिकेशन अपडेट में 'ब्लू/ग्रीन डिप्लॉयमेंट' क्या है?",opts:["एप्लिकेशन के CSS रंग बदलना","एक रिलीज तकनीक जो दो समान उत्पादन वातावरण चलाकर डाउनटाइम और जोखिम को कम करती है","समुद्र और जंगल में सर्वर तैनात करना","पुराने सर्वरों को रीसाइक्लिंग करना"],ans:1,exp:"ब्लू/ग्रीन डिप्लॉयमेंट एक ऐसी तकनीक है जिसमें दो समान उत्पादन वातावरण (ब्लू और ग्रीन) चलाना शामिल है। एक बार में केवल एक ही लाइव ट्रैफ़िक परोसता है। नए कोड को निष्क्रिय वातावरण में तैनात किया जाता है, फिर ट्रैफ़िक बदल दिया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"What role does 'Load Balancing' play in cloud architecture?",opts:["It adds extra weight to physical servers","It distributes incoming network traffic across multiple servers to ensure no single server becomes overwhelmed","It downloads data faster","It compresses database tables"],ans:1,exp:"Load Balancing efficiently distributes incoming network traffic across a group of backend servers. This prevents any single server from becoming a bottleneck, ensuring application responsiveness and high availability. It is crucial for highly scalable web applications."},hi:{q:"क्लाउड आर्किटेक्चर में 'लोड बैलेंसिंग' क्या भूमिका निभाता है?",opts:["यह भौतिक सर्वरों में अतिरिक्त वजन जोड़ता है","यह सुनिश्चित करने के लिए कई सर्वरों में आने वाले नेटवर्क ट्रैफ़िक को वितरित करता है कि कोई एक सर्वर अभिभूत न हो","यह डेटा तेजी से डाउनलोड करता है","यह डेटाबेस तालिकाओं को संपीड़ित करता है"],ans:1,exp:"लोड बैलेंसिंग बैकएंड सर्वर के समूह में आने वाले नेटवर्क ट्रैफ़िक को कुशलतापूर्वक वितरित करता है। यह किसी भी एक सर्वर को बाधा बनने से रोकता है, एप्लिकेशन जवाबदेही और उच्च उपलब्धता सुनिश्चित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which of the following describes 'Black-box testing'?",opts:["Testing without knowledge of the internal code or structure","Testing by analyzing the source code line by line","Testing hardware servers exclusively","Testing performed only at night"],ans:0,exp:"Black-box testing is a method of software testing that examines the functionality of an application without peering into its internal structures or workings. The tester focuses solely on the inputs and expected outputs, mimicking an end-user's interaction."},hi:{q:"निम्नलिखित में से कौन सा 'ब्लैक-बॉक्स परीक्षण' का वर्णन करता है?",opts:["आंतरिक कोड या संरचना के ज्ञान के बिना परीक्षण","लाइन दर लाइन सोर्स कोड का विश्लेषण करके परीक्षण","विशेष रूप से हार्डवेयर सर्वर का परीक्षण","परीक्षण केवल रात में किया जाता है"],ans:0,exp:"ब्लैक-बॉक्स परीक्षण सॉफ्टवेयर परीक्षण की एक विधि है जो अपने आंतरिक संरचनाओं में झांके बिना एप्लिकेशन की कार्यक्षमता की जांच करती है। परीक्षक पूरी तरह से इनपुट और अपेक्षित आउटपुट पर ध्यान केंद्रित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"What is Docker used for in modern application development?",opts:["Creating hardware layouts","Containerizing applications so they can run reliably in any computing environment","Writing documentation","Graphic designing"],ans:1,exp:"Docker is an open-source platform that enables developers to automate the deployment of applications inside lightweight, portable containers. Containers bundle the application code with all its dependencies. This ensures consistency from development to cloud production environments."},hi:{q:"आधुनिक एप्लिकेशन विकास में Docker का उपयोग किस लिए किया जाता है?",opts:["हार्डवेयर लेआउट बनाना","अनुप्रयोगों को कंटेनर बनाना ताकि वे किसी भी कंप्यूटिंग वातावरण में मज़बूती से चल सकें","प्रलेखन लिखना","ग्राफिक डिजाइनिंग"],ans:1,exp:"डॉकर एक ओपन-सोर्स प्लेटफ़ॉर्म है जो डेवलपर्स को हल्के, पोर्टेबल कंटेनरों के अंदर अनुप्रयोगों की तैनाती को स्वचालित करने में सक्षम बनाता है। कंटेनर एप्लिकेशन कोड को उसकी सभी निर्भरताओं के साथ बंडल करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Which SDLC phase evaluates the legacy system and decides if a completely new system is required?",opts:["System Design","Preliminary Investigation / Feasibility Study","Testing","Deployment"],ans:1,exp:"The Preliminary Investigation (or Feasibility Study) phase evaluates the current system's problems and determines if building a new system or upgrading the old one is viable. It analyzes the cost-benefit ratio. Management uses this to approve or scrap the project."},hi:{q:"कौन सा SDLC चरण विरासत प्रणाली का मूल्यांकन करता है और यह तय करता है कि क्या पूरी तरह से नई प्रणाली की आवश्यकता है?",opts:["सिस्टम डिजाइन","प्रारंभिक जांच / व्यवहार्यता अध्ययन","परीक्षण","डिप्लॉयमेंट"],ans:1,exp:"प्रारंभिक जांच चरण वर्तमान प्रणाली की समस्याओं का मूल्यांकन करता है और यह निर्धारित करता है कि एक नई प्रणाली का निर्माण करना व्यावहारिक है या नहीं। यह लागत-लाभ अनुपात का विश्लेषण करता है।"}},
{type:"mcq",diff:"hard",en:{q:"What is 'Content Delivery Network' (CDN) in relation to cloud applications?",opts:["A network of delivery trucks for hardware","A geographically distributed group of servers that work together to provide fast delivery of Internet content","A local LAN connection","A new HTML tag"],ans:1,exp:"A CDN is a network of servers distributed globally to deliver web content rapidly to users by caching it closer to their physical location. It drastically reduces latency and load times for cloud applications. Cloud providers often offer integrated CDN services."},hi:{q:"क्लाउड एप्लिकेशन के संबंध में 'कंटेंट डिलीवरी नेटवर्क' (CDN) क्या है?",opts:["हार्डवेयर के लिए डिलीवरी ट्रकों का एक नेटवर्क","सर्वरों का भौगोलिक रूप से वितरित समूह जो इंटरनेट सामग्री की तेजी से डिलीवरी प्रदान करने के लिए एक साथ काम करते हैं","एक स्थानीय LAN कनेक्शन","एक नया HTML टैग"],ans:1,exp:"एक CDN विश्व स्तर पर वितरित सर्वरों का एक नेटवर्क है जो वेब सामग्री को उपयोगकर्ताओं के भौतिक स्थान के करीब कैश करके उन्हें तेज़ी से वितरित करता है। यह क्लाउड अनुप्रयोगों के लिए विलंबता को कम करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which of the following is a key characteristic of RESTful APIs used in cloud apps?",opts:["They maintain a constant state connection","They are stateless, meaning each request contains all the information needed by the server to fulfill it","They can only be used with XML","They require physical hardware keys"],ans:1,exp:"RESTful APIs are stateless, meaning the server does not store any state about the client session on the server side. Every request from the client must contain all the necessary information. This statelessness makes cloud applications highly scalable."},hi:{q:"क्लाउड ऐप में उपयोग किए जाने वाले RESTful API की प्रमुख विशेषता निम्नलिखित में से कौन सी है?",opts:["वे निरंतर राज्य कनेक्शन बनाए रखते हैं","वे स्टेटलेस हैं, जिसका अर्थ है कि प्रत्येक अनुरोध में सर्वर द्वारा आवश्यक सभी जानकारी होती है","उनका उपयोग केवल XML के साथ किया जा सकता है","उन्हें भौतिक हार्डवेयर कुंजियों की आवश्यकता होती है"],ans:1,exp:"RESTful API स्टेटलेस होते हैं, जिसका अर्थ है कि सर्वर क्लाइंट सत्र के बारे में कोई स्थिति संग्रहीत नहीं करता है। क्लाइंट के प्रत्येक अनुरोध में सभी आवश्यक जानकारी होनी चाहिए। यह क्लाउड अनुप्रयोगों को अत्यधिक स्केलेबल बनाता है।"}},
{type:"mcq",diff:"hard",en:{q:"In Agile methodology, what is the role of the 'Scrum Master'?",opts:["To write the core database logic","To facilitate the Scrum process, remove impediments, and ensure the team follows Agile practices","To fund the project","To sell the software"],ans:1,exp:"The Scrum Master acts as a servant-leader for the Agile team. They organize daily meetings, manage sprint planning, and remove obstacles that hinder the team's progress. They do not manage the team conventionally but facilitate the Agile process."},hi:{q:"एजाइल पद्धति में, 'स्क्रम मास्टर' (Scrum Master) की क्या भूमिका है?",opts:["कोर डेटाबेस लॉजिक लिखना","स्क्रम प्रक्रिया को सुविधाजनक बनाना, बाधाओं को दूर करना और यह सुनिश्चित करना कि टीम एजाइल प्रथाओं का पालन करती है","परियोजना को निधि देना","सॉफ्टवेयर बेचना"],ans:1,exp:"स्क्रम मास्टर एजाइल टीम के लिए एक सेवक-नेता के रूप में कार्य करता है। वे दैनिक बैठकों का आयोजन करते हैं और उन बाधाओं को दूर करते हैं जो टीम की प्रगति में बाधा डालती हैं। वे एजाइल प्रक्रिया को सुविधाजनक बनाते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"What does the 'Software Requirement Specification' (SRS) document NOT contain?",opts:["Functional requirements","Non-functional requirements","The exact source code of the final application","System interfaces"],ans:2,exp:"The SRS document contains functional, non-functional requirements, use cases, and system interfaces. It details *what* the system should do, not *how* to code it. The actual source code is written much later in the implementation phase."},hi:{q:"'सॉफ्टवेयर आवश्यकता विशिष्टता' (SRS) दस्तावेज़ में क्या शामिल नहीं है?",opts:["कार्यात्मक आवश्यकताएं","गैर-कार्यात्मक आवश्यकताएं","अंतिम एप्लिकेशन का सटीक स्रोत कोड","सिस्टम इंटरफेस"],ans:2,exp:"SRS दस्तावेज़ में कार्यात्मक, गैर-कार्यात्मक आवश्यकताएं और सिस्टम इंटरफेस शामिल हैं। यह विवरण देता है कि सिस्टम को क्या करना चाहिए, न कि इसे कैसे कोड करना है। वास्तविक स्रोत कोड कार्यान्वयन चरण में बहुत बाद में लिखा जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which of the following is a threat to cloud computing security where a malicious user creates a fake website to steal credentials?",opts:["DDoS","Phishing","Buffer Overflow","SQL Injection"],ans:1,exp:"Phishing is a social engineering attack where a hacker masquerades as a trusted entity to deceive a victim into revealing sensitive information like login credentials. It is a major threat to cloud accounts. Users must verify URLs to prevent falling victim."},hi:{q:"निम्नलिखित में से कौन सा क्लाउड कंप्यूटिंग सुरक्षा के लिए खतरा है जहां एक दुर्भावनापूर्ण उपयोगकर्ता क्रेडेंशियल चुराने के लिए नकली वेबसाइट बनाता है?",opts:["DDoS","फ़िशिंग (Phishing)","बफर ओवरफ्लो","SQL इंजेक्शन"],ans:1,exp:"फ़िशिंग एक सामाजिक इंजीनियरिंग हमला है जहां एक हैकर लॉग-इन क्रेडेंशियल जैसी संवेदनशील जानकारी प्रकट करने के लिए पीड़ित को धोखा देने के लिए एक विश्वसनीय इकाई के रूप में प्रच्छन्न होता है। यह क्लाउड खातों के लिए एक बड़ा खतरा है।"}},
{type:"mcq",diff:"hard",en:{q:"What is 'Regression Testing'?",opts:["Testing older software to see if it still works on Windows 95","Testing the system after a code change to ensure that the new code hasn't adversely affected existing features","Testing how fast the software crashes","Testing the hardware components"],ans:1,exp:"Regression Testing is executed after modifying the software to confirm that a recent program or code change has not adversely affected existing features. It involves re-running previously passed test cases. Automated testing tools are heavily used for regression testing."},hi:{q:"'प्रतिगमन परीक्षण' (Regression Testing) क्या है?",opts:["यह देखने के लिए पुराने सॉफ़्टवेयर का परीक्षण करना कि क्या यह अभी भी विंडोज 95 पर काम करता है","कोड बदलने के बाद यह सुनिश्चित करने के लिए सिस्टम का परीक्षण करना कि नए कोड ने मौजूदा सुविधाओं पर प्रतिकूल प्रभाव नहीं डाला है","परीक्षण करना कि सॉफ्टवेयर कितनी तेजी से क्रैश होता है","हार्डवेयर घटकों का परीक्षण"],ans:1,exp:"प्रतिगमन परीक्षण यह पुष्टि करने के लिए सॉफ़्टवेयर को संशोधित करने के बाद निष्पादित किया जाता है कि हाल ही के कोड परिवर्तन ने मौजूदा सुविधाओं पर प्रतिकूल प्रभाव नहीं डाला है। इसमें पहले से पास किए गए परीक्षण मामलों को फिर से चलाना शामिल है।"}},
{type:"mcq",diff:"hard",en:{q:"Which of these describes a 'Serverless' database in the cloud?",opts:["A database stored on a CD-ROM","A database service that automatically scales capacity and computes based on application demand without manual server provisioning","A database that deletes its data automatically","A local MS Access file"],ans:1,exp:"A serverless database (like Amazon Aurora Serverless) automatically starts up, shuts down, and scales capacity up or down based on application needs. Developers don't manage database instances or clusters. You pay only for the database capacity consumed."},hi:{q:"इनमें से कौन क्लाउड में 'सर्वरलेस' डेटाबेस का वर्णन करता है?",opts:["CD-ROM पर संग्रहीत डेटाबेस","एक डेटाबेस सेवा जो मैन्युअल सर्वर प्रोविज़निंग के बिना एप्लिकेशन की मांग के आधार पर स्वचालित रूप से क्षमता और गणना को बढ़ाती है","एक डेटाबेस जो अपना डेटा स्वचालित रूप से हटा देता है","एक स्थानीय MS Access फ़ाइल"],ans:1,exp:"एक सर्वरलेस डेटाबेस स्वचालित रूप से शुरू होता है, बंद हो जाता है, और एप्लिकेशन की ज़रूरतों के आधार पर क्षमता को ऊपर या नीचे स्केल करता है। डेवलपर्स डेटाबेस उदाहरणों का प्रबंधन नहीं करते हैं। आप केवल खपत क्षमता के लिए भुगतान करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"In Cloud Identity and Access Management (IAM), what is 'Role-Based Access Control' (RBAC)?",opts:["Giving everyone full admin access","Assigning system access based on the user's role within the organization","Restricting access based on physical location only","Access based on random assignment"],ans:1,exp:"RBAC restricts network access based on the roles of individual users within an enterprise. It ensures that employees access only the information necessary to perform their specific duties. This strictly enforces the principle of least privilege in cloud environments."},hi:{q:"क्लाउड आइडेंटिटी एंड एक्सेस मैनेजमेंट (IAM) में, 'रोल-बेस्ड एक्सेस कंट्रोल' (RBAC) क्या है?",opts:["सभी को पूर्ण व्यवस्थापक पहुंच प्रदान करना","संगठन के भीतर उपयोगकर्ता की भूमिका के आधार पर सिस्टम एक्सेस प्रदान करना","केवल भौतिक स्थान के आधार पर पहुंच को प्रतिबंधित करना","यादृच्छिक असाइनमेंट के आधार पर प्रवेश"],ans:1,exp:"RBAC उद्यम के भीतर व्यक्तिगत उपयोगकर्ताओं की भूमिकाओं के आधार पर नेटवर्क एक्सेस को प्रतिबंधित करता है। यह सुनिश्चित करता है कि कर्मचारी केवल अपने विशिष्ट कर्तव्यों को पूरा करने के लिए आवश्यक जानकारी तक ही पहुँचें।"}},
{type:"mcq",diff:"hard",en:{q:"What does the 'Big Bang' deployment strategy mean?",opts:["Replacing the entire old system with the new system instantly across the organization","Deploying the system incrementally in phases","Deploying the system to only one department first","Blowing up old servers"],ans:0,exp:"In a Big Bang deployment, the new system is completely rolled out and the old system is retired simultaneously on a specific date. It is highly risky because any critical failure affects all users immediately. However, it avoids maintaining two systems simultaneously."},hi:{q:"'बिग बैंग' डिप्लॉयमेंट रणनीति का क्या अर्थ है?",opts:["पूरे संगठन में तुरंत नई प्रणाली के साथ पूरी पुरानी प्रणाली को बदलना","सिस्टम को चरणों में वृद्धिशील रूप से तैनात करना","पहले केवल एक विभाग में सिस्टम तैनात करना","पुराने सर्वरों को उड़ाना"],ans:0,exp:"बिग बैंग परिनियोजन में, नई प्रणाली पूरी तरह से शुरू की जाती है और पुरानी प्रणाली को एक साथ एक विशिष्ट तिथि पर सेवानिवृत्त किया जाता है। यह अत्यधिक जोखिम भरा है लेकिन एक साथ दो प्रणालियों को बनाए रखने से बचा जाता है।"}},
{type:"tf",diff:"hard",en:{q:"In the Spiral SDLC model, risk analysis is a minor and optional step.",opts:["True","False"],ans:1,exp:"False. The Spiral model is highly risk-driven. Each iteration (spiral) involves rigorous risk analysis and resolution before proceeding to the next phase of development. It is used for large, expensive, and complicated projects."},hi:{q:"स्पाइरल SDLC मॉडल में, जोखिम विश्लेषण एक मामूली और वैकल्पिक कदम है।",opts:["सही","गलत"],ans:1,exp:"गलत। स्पाइरल मॉडल अत्यधिक जोखिम-संचालित है। विकास के अगले चरण में आगे बढ़ने से पहले प्रत्येक पुनरावृत्ति (सर्पिल) में कठोर जोखिम विश्लेषण शामिल होता है। इसका उपयोग बड़ी और जटिल परियोजनाओं के लिए किया जाता है।"}},
{type:"tf",diff:"hard",en:{q:"Cloud computing entirely eliminates the risk of data loss and security breaches.",opts:["True","False"],ans:1,exp:"False. While cloud providers offer advanced security, storing data externally introduces risks like misconfiguration, insider threats at the vendor, and credential theft. Customers must actively manage their security configurations under the shared responsibility model."},hi:{q:"क्लाउड कंप्यूटिंग पूरी तरह से डेटा हानि और सुरक्षा उल्लंघनों के जोखिम को समाप्त करता है।",opts:["सही","गलत"],ans:1,exp:"गलत। जबकि क्लाउड प्रदाता उन्नत सुरक्षा प्रदान करते हैं, बाहरी रूप से डेटा संग्रहीत करने से गलत कॉन्फ़िगरेशन जैसे जोखिम पेश होते हैं। ग्राहकों को साझा जिम्मेदारी मॉडल के तहत अपने सुरक्षा कॉन्फ़िगरेशन को सक्रिय रूप से प्रबंधित करना चाहिए।"}}
];
